111	void CCoinsViewCache::EmplaceCoinInternalDANGER(COutPoint&& outpoint, Coin&& coin) {
112	    const auto mem_usage{coin.DynamicMemoryUsage()};
113	    auto [it, inserted] = cacheCoins.try_emplace(std::move(outpoint), std::move(coin));
114	    if (inserted) {
