121	void AddCoins(CCoinsViewCache& cache, const CTransaction &tx, int nHeight, bool check_for_overwrite) {
122	    bool fCoinbase = tx.IsCoinBase();
123	    const Txid& txid = tx.GetHash();
124	    for (size_t i = 0; i < tx.vout.size(); ++i) {
125	        bool overwrite = check_for_overwrite ? cache.HaveCoin(COutPoint(txid, i)) : fCoinbase;
126	        // Coinbase transactions can always be overwritten, in order to correctly
127	        // deal with the pre-BIP30 occurrences of duplicate coinbase transactions.
128	        cache.AddCoin(COutPoint(txid, i), Coin(tx.vout[i], nHeight, fCoinbase), overwrite);
129	    }
130	}
