260	void CCoinsViewCache::Flush(bool reallocate_cache)
261	{
262	    auto cursor{CoinsViewCacheCursor(m_dirty_count, m_sentinel, cacheCoins, /*will_erase=*/true)};
263	    base->BatchWrite(cursor, m_block_hash);
264	    Assume(m_dirty_count == 0);
265	    cacheCoins.clear();
266	    if (reallocate_cache) {
267	        ReallocateCache();
268	    }
269	    cachedCoinsUsage = 0;
270	}
