4917	            vAddr = m_connman.GetAddressesUnsafe(MAX_ADDR_TO_SEND, MAX_PCT_ADDR_TO_SEND, /*network=*/std::nullopt);
4918	        } else {
4919	            vAddr = m_connman.GetAddresses(pfrom, MAX_ADDR_TO_SEND, MAX_PCT_ADDR_TO_SEND);
4920	        }
4921	        for (const CAddress &addr : vAddr) {
4922	            PushAddress(peer, addr);
4923	        }
4924	        return;
4925	    }
4926	
4927	    if (msg_type == NetMsgType::MEMPOOL) {
4928	        // Only process received mempool messages if we advertise NODE_BLOOM
4929	        // or if the peer has mempool permissions.
4930	        if (!(peer.m_our_services & NODE_BLOOM) && !pfrom.HasPermission(NetPermissionFlags::Mempool))
4931	        {
4932	            if (!pfrom.HasPermission(NetPermissionFlags::NoBan))
4933	            {
4934	                LogDebug(BCLog::NET, "mempool request with bloom filters disabled, %s", pfrom.DisconnectMsg());
4935	                pfrom.fDisconnect = true;
4936	            }
4937	            return;
4938	        }
4939	
4940	        if (m_connman.OutboundTargetReached(false) && !pfrom.HasPermission(NetPermissionFlags::Mempool))
4941	        {
4942	            if (!pfrom.HasPermission(NetPermissionFlags::NoBan))
4943	            {
4944	                LogDebug(BCLog::NET, "mempool request with bandwidth limit reached, %s", pfrom.DisconnectMsg());
4945	                pfrom.fDisconnect = true;
4946	            }
4947	            return;
4948	        }
4949	
4950	        if (auto tx_relay = peer.GetTxRelay(); tx_relay != nullptr) {
4951	            LOCK(tx_relay->m_tx_inventory_mutex);
4952	            tx_relay->m_send_mempool = true;
4953	        }
4954	        return;
4955	    }
4956	
4957	    if (msg_type == NetMsgType::PING) {
4958	        if (pfrom.GetCommonVersion() > BIP0031_VERSION) {
4959	            uint64_t nonce = 0;
4960	            vRecv >> nonce;
4961	            // Echo the message back with the nonce. This allows for two useful features:
4962	            //
4963	            // 1) A remote node can quickly check if the connection is operational
4964	            // 2) Remote nodes can measure the latency of the network thread. If this node
4965	            //    is overloaded it won't respond to pings quickly and the remote node can
4966	            //    avoid sending us more work, like chain download requests.
4967	            //
4968	            // The nonce stops the remote getting confused between different pings: without
4969	            // it, if the remote node sends a ping once per second and this node takes 5
4970	            // seconds to respond to each, the 5th ping the remote sends would appear to
4971	            // return very quickly.
4972	            MakeAndPushMessage(pfrom, NetMsgType::PONG, nonce);
4973	        }
4974	        return;
4975	    }
4976	
4977	    if (msg_type == NetMsgType::PONG) {
4978	        ProcessPong(pfrom, peer, /*ping_end=*/time_received, vRecv);
4979	        return;
4980	    }
4981	
4982	    if (msg_type == NetMsgType::FILTERLOAD) {
4983	        if (!(peer.m_our_services & NODE_BLOOM)) {
4984	            LogDebug(BCLog::NET, "filterload received despite not offering bloom services, %s", pfrom.DisconnectMsg());
4985	            pfrom.fDisconnect = true;
4986	            return;
4987	        }
4988	        CBloomFilter filter;
4989	        vRecv >> filter;
4990	
4991	        if (!filter.IsWithinSizeConstraints())
4992	        {
4993	            // There is no excuse for sending a too-large filter
4994	            Misbehaving(peer, "too-large bloom filter");
4995	        } else if (auto tx_relay = peer.GetTxRelay(); tx_relay != nullptr) {
4996	            {
4997	                LOCK(tx_relay->m_bloom_filter_mutex);
4998	                tx_relay->m_bloom_filter.reset(new CBloomFilter(filter));
4999	                tx_relay->m_relay_txs = true;
5000	            }
5001	            pfrom.m_bloom_filter_loaded = true;
5002	            pfrom.m_relays_txs = true;
5003	        }
5004	        return;
5005	    }
5006	
5007	    if (msg_type == NetMsgType::FILTERADD) {
5008	        if (!(peer.m_our_services & NODE_BLOOM)) {
5009	            LogDebug(BCLog::NET, "filteradd received despite not offering bloom services, %s", pfrom.DisconnectMsg());
5010	            pfrom.fDisconnect = true;
5011	            return;
5012	        }
5013	        std::vector<unsigned char> vData;
5014	        vRecv >> vData;
5015	
5016	        // Nodes must NEVER send a data item > MAX_SCRIPT_ELEMENT_SIZE bytes (the max size for a script data object,
5017	        // and thus, the maximum size any matched object can have) in a filteradd message
5018	        bool bad = false;
5019	        if (vData.size() > MAX_SCRIPT_ELEMENT_SIZE) {
5020	            bad = true;
5021	        } else if (auto tx_relay = peer.GetTxRelay(); tx_relay != nullptr) {
5022	            LOCK(tx_relay->m_bloom_filter_mutex);
5023	            if (tx_relay->m_bloom_filter) {
5024	                tx_relay->m_bloom_filter->insert(vData);
5025	            } else {
5026	                bad = true;
5027	            }
5028	        }
5029	        if (bad) {
5030	            Misbehaving(peer, "bad filteradd message");
5031	        }
5032	        return;
5033	    }
5034	
5035	    if (msg_type == NetMsgType::FILTERCLEAR) {
5036	        if (!(peer.m_our_services & NODE_BLOOM)) {
5037	            LogDebug(BCLog::NET, "filterclear received despite not offering bloom services, %s", pfrom.DisconnectMsg());
5038	            pfrom.fDisconnect = true;
5039	            return;
5040	        }
5041	        auto tx_relay = peer.GetTxRelay();
5042	        if (!tx_relay) return;
5043	
5044	        {
5045	            LOCK(tx_relay->m_bloom_filter_mutex);
5046	            tx_relay->m_bloom_filter = nullptr;
5047	            tx_relay->m_relay_txs = true;
5048	        }
5049	        pfrom.m_bloom_filter_loaded = false;
5050	        pfrom.m_relays_txs = true;
5051	        return;
5052	    }
5053	
5054	    if (msg_type == NetMsgType::FEEFILTER) {
5055	        CAmount newFeeFilter = 0;
5056	        vRecv >> newFeeFilter;
5057	        if (MoneyRange(newFeeFilter)) {
5058	            if (auto tx_relay = peer.GetTxRelay(); tx_relay != nullptr) {
5059	                tx_relay->m_fee_filter_received = newFeeFilter;
5060	            }
5061	            LogDebug(BCLog::NET, "received: feefilter of %s from peer=%d\n", CFeeRate(newFeeFilter).ToString(), pfrom.GetId());
5062	        }
5063	        return;
5064	    }
5065	
5066	    if (msg_type == NetMsgType::GETCFILTERS) {
5067	        ProcessGetCFilters(pfrom, peer, vRecv);
5068	        return;
5069	    }
5070	
5071	    if (msg_type == NetMsgType::GETCFHEADERS) {
5072	        ProcessGetCFHeaders(pfrom, peer, vRecv);
5073	        return;
5074	    }
5075	
5076	    if (msg_type == NetMsgType::GETCFCHECKPT) {
5077	        ProcessGetCFCheckPt(pfrom, peer, vRecv);
5078	        return;
5079	    }
5080	
5081	    if (msg_type == NetMsgType::NOTFOUND) {
5082	        std::vector<CInv> vInv;
5083	        vRecv >> vInv;
5084	        std::vector<GenTxid> tx_invs;
5085	        if (vInv.size() <= node::MAX_PEER_TX_ANNOUNCEMENTS + MAX_BLOCKS_IN_TRANSIT_PER_PEER) {
5086	            for (CInv &inv : vInv) {
5087	                if (inv.IsGenTxMsg()) {
5088	                    tx_invs.emplace_back(ToGenTxid(inv));
5089	                }
5090	            }
5091	        }
5092	        LOCK(m_tx_download_mutex);
5093	        m_txdownloadman.ReceivedNotFound(pfrom.GetId(), tx_invs);
5094	        return;
5095	    }
5096	
5097	    // Ignore unknown message types for extensibility
5098	    LogDebug(BCLog::NET, "Unknown message type \"%s\" from peer=%d", SanitizeString(msg_type), pfrom.GetId());
5099	    return;
5100	}
