5102	bool PeerManagerImpl::MaybeDiscourageAndDisconnect(CNode& pnode, Peer& peer)
5103	{
5104	    {
5105	        LOCK(peer.m_misbehavior_mutex);
5106	
5107	        // There's nothing to do if the m_should_discourage flag isn't set
5108	        if (!peer.m_should_discourage) return false;
5109	
5110	        peer.m_should_discourage = false;
5111	    } // peer.m_misbehavior_mutex
5112	
5113	    if (pnode.HasPermission(NetPermissionFlags::NoBan)) {
5114	        // We never disconnect or discourage peers for bad behavior if they have NetPermissionFlags::NoBan permission
5115	        LogWarning("Not punishing noban peer %d!", peer.m_id);
5116	        return false;
5117	    }
5118	
5119	    if (pnode.IsManualConn()) {
5120	        // We never disconnect or discourage manual peers for bad behavior
5121	        LogWarning("Not punishing manually connected peer %d!", peer.m_id);
5122	        return false;
5123	    }
5124	
5125	    if (pnode.addr.IsLocal()) {
5126	        // We disconnect local peers for bad behavior but don't discourage (since that would discourage
5127	        // all peers on the same local address)
5128	        LogDebug(BCLog::NET, "Warning: disconnecting but not discouraging %s peer %d!\n",
5129	                 pnode.m_inbound_onion ? "inbound onion" : "local", peer.m_id);
5130	        pnode.fDisconnect = true;
5131	        return true;
5132	    }
5133	
5134	    // Normal case: Disconnect the peer and discourage all nodes sharing the address
5135	    LogDebug(BCLog::NET, "Disconnecting and discouraging peer %d!\n", peer.m_id);
5136	    if (m_banman) m_banman->Discourage(pnode.addr);
5137	    m_connman.DisconnectNode(pnode.addr);
5138	    return true;
5139	}
