5141	bool PeerManagerImpl::ProcessMessages(CNode& node, std::atomic<bool>& interruptMsgProc)
5142	{
5143	    AssertLockNotHeld(m_tx_download_mutex);
5144	    AssertLockHeld(g_msgproc_mutex);
5145	
5146	    PeerRef maybe_peer{GetPeerRef(node.GetId())};
5147	    if (maybe_peer == nullptr) return false;
5148	    Peer& peer{*maybe_peer};
5149	
5150	    // For outbound connections, ensure that the initial VERSION message
5151	    // has been sent first before processing any incoming messages
5152	    if (!node.IsInboundConn() && !peer.m_outbound_version_message_sent) return false;
5153	
5154	    {
5155	        LOCK(peer.m_getdata_requests_mutex);
5156	        if (!peer.m_getdata_requests.empty()) {
5157	            ProcessGetData(node, peer, interruptMsgProc);
5158	        }
5159	    }
5160	
5161	    const bool processed_orphan = ProcessOrphanTx(peer);
5162	
5163	    if (node.fDisconnect)
5164	        return false;
5165	
5166	    if (processed_orphan) return true;
5167	
5168	    // this maintains the order of responses
5169	    // and prevents m_getdata_requests to grow unbounded
5170	    {
5171	        LOCK(peer.m_getdata_requests_mutex);
5172	        if (!peer.m_getdata_requests.empty()) return true;
5173	    }
5174	
5175	    // Don't bother if send buffer is too full to respond anyway
5176	    if (node.fPauseSend) return false;
5177	
5178	    auto poll_result{node.PollMessage()};
5179	    if (!poll_result) {
5180	        // No message to process
5181	        return false;
5182	    }
5183	
5184	    CNetMessage& msg{poll_result->first};
5185	    bool fMoreWork = poll_result->second;
5186	
5187	    TRACEPOINT(net, inbound_message,
5188	        node.GetId(),
5189	        node.m_addr_name.c_str(),
5190	        node.ConnectionTypeAsString().c_str(),
5191	        msg.m_type.c_str(),
5192	        msg.m_recv.size(),
5193	        msg.m_recv.data()
5194	    );
5195	
5196	    if (m_opts.capture_messages) {
5197	        CaptureMessage(node.addr, msg.m_type, MakeUCharSpan(msg.m_recv), /*is_incoming=*/true);
5198	    }
5199	
5200	    try {
5201	        ProcessMessage(peer, node, msg.m_type, msg.m_recv, msg.m_time, interruptMsgProc);
5202	        if (interruptMsgProc) return false;
5203	        {
5204	            LOCK(peer.m_getdata_requests_mutex);
5205	            if (!peer.m_getdata_requests.empty()) fMoreWork = true;
5206	        }
5207	        // Does this peer have an orphan ready to reconsider?
5208	        // (Note: we may have provided a parent for an orphan provided
5209	        //  by another peer that was already processed; in that case,
5210	        //  the extra work may not be noticed, possibly resulting in an
5211	        //  unnecessary 100ms delay)
5212	        LOCK(m_tx_download_mutex);
5213	        if (m_txdownloadman.HaveMoreWork(peer.m_id)) fMoreWork = true;
5214	    } catch (const std::exception& e) {
5215	        LogDebug(BCLog::NET, "%s(%s, %u bytes): Exception '%s' (%s) caught\n", __func__, SanitizeString(msg.m_type), msg.m_message_size, e.what(), typeid(e).name());
5216	    } catch (...) {
5217	        LogDebug(BCLog::NET, "%s(%s, %u bytes): Unknown exception caught\n", __func__, SanitizeString(msg.m_type), msg.m_message_size);
5218	    }
5219	
5220	    return fMoreWork;
5221	}
