5223	void PeerManagerImpl::ConsiderEviction(CNode& pto, Peer& peer, std::chrono::seconds time_in_seconds)
5224	{
5225	    AssertLockHeld(cs_main);
5226	
5227	    CNodeState &state = *State(pto.GetId());
5228	
5229	    if (!state.m_chain_sync.m_protect && pto.IsOutboundOrBlockRelayConn() && state.fSyncStarted) {
5230	        // This is an outbound peer subject to disconnection if they don't
5231	        // announce a block with as much work as the current tip within
5232	        // CHAIN_SYNC_TIMEOUT + HEADERS_RESPONSE_TIME seconds (note: if
5233	        // their chain has more work than ours, we should sync to it,
5234	        // unless it's invalid, in which case we should find that out and
5235	        // disconnect from them elsewhere).
5236	        if (state.pindexBestKnownBlock != nullptr && state.pindexBestKnownBlock->nChainWork >= m_chainman.ActiveChain().Tip()->nChainWork) {
5237	            // The outbound peer has sent us a block with at least as much work as our current tip, so reset the timeout if it was set
5238	            if (state.m_chain_sync.m_timeout != 0s) {
5239	                state.m_chain_sync.m_timeout = 0s;
5240	                state.m_chain_sync.m_work_header = nullptr;
5241	                state.m_chain_sync.m_sent_getheaders = false;
5242	            }
5243	        } else if (state.m_chain_sync.m_timeout == 0s || (state.m_chain_sync.m_work_header != nullptr && state.pindexBestKnownBlock != nullptr && state.pindexBestKnownBlock->nChainWork >= state.m_chain_sync.m_work_header->nChainWork)) {
5244	            // At this point we know that the outbound peer has either never sent us a block/header or they have, but its tip is behind ours
5245	            // AND
5246	            // we are noticing this for the first time (m_timeout is 0)
5247	            // OR we noticed this at some point within the last CHAIN_SYNC_TIMEOUT + HEADERS_RESPONSE_TIME seconds and set a timeout
5248	            // for them, they caught up to our tip at the time of setting the timer but not to our current one (we've also advanced).
5249	            // Either way, set a new timeout based on our current tip.
5250	            state.m_chain_sync.m_timeout = time_in_seconds + CHAIN_SYNC_TIMEOUT;
5251	            state.m_chain_sync.m_work_header = m_chainman.ActiveChain().Tip();
5252	            state.m_chain_sync.m_sent_getheaders = false;
5253	        } else if (state.m_chain_sync.m_timeout > 0s && time_in_seconds > state.m_chain_sync.m_timeout) {
5254	            // No evidence yet that our peer has synced to a chain with work equal to that
5255	            // of our tip, when we first detected it was behind. Send a single getheaders
5256	            // message to give the peer a chance to update us.
5257	            if (state.m_chain_sync.m_sent_getheaders) {
5258	                // They've run out of time to catch up!
5259	                LogInfo("Outbound peer has old chain, best known block = %s, %s", state.pindexBestKnownBlock != nullptr ? state.pindexBestKnownBlock->GetBlockHash().ToString() : "<none>", pto.DisconnectMsg());
5260	                pto.fDisconnect = true;
5261	            } else {
5262	                assert(state.m_chain_sync.m_work_header);
5263	                // Here, we assume that the getheaders message goes out,
5264	                // because it'll either go out or be skipped because of a
5265	                // getheaders in-flight already, in which case the peer should
5266	                // still respond to us with a sufficiently high work chain tip.
5267	                MaybeSendGetHeaders(pto,
5268	                        GetLocator(state.m_chain_sync.m_work_header->pprev),
5269	                        peer);
5270	                LogDebug(BCLog::NET, "sending getheaders to outbound peer=%d to verify chain work (current best known block:%s, benchmark blockhash: %s)\n", pto.GetId(), state.pindexBestKnownBlock != nullptr ? state.pindexBestKnownBlock->GetBlockHash().ToString() : "<none>", state.m_chain_sync.m_work_header->GetBlockHash().ToString());
5271	                state.m_chain_sync.m_sent_getheaders = true;
5272	                // Bump the timeout to allow a response, which could clear the timeout
5273	                // (if the response shows the peer has synced), reset the timeout (if
5274	                // the peer syncs to the required work but not to our tip), or result
5275	                // in disconnect (if we advance to the timeout and pindexBestKnownBlock
5276	                // has not sufficiently progressed)
5277	                state.m_chain_sync.m_timeout = time_in_seconds + HEADERS_RESPONSE_TIME;
5278	            }
5279	        }
5280	    }
5281	}
5282	
5283	void PeerManagerImpl::EvictExtraOutboundPeers(NodeClock::time_point now)
5284	{
5285	    // If we have any extra block-relay-only peers, disconnect the youngest unless
5286	    // it's given us a block -- in which case, compare with the second-youngest, and
5287	    // out of those two, disconnect the peer who least recently gave us a block.
5288	    // The youngest block-relay-only peer would be the extra peer we connected
5289	    // to temporarily in order to sync our tip; see net.cpp.
5290	    // Note that we use higher nodeid as a measure for most recent connection.
5291	    if (m_connman.GetExtraBlockRelayCount() > 0) {
5292	        std::pair<NodeId, std::chrono::seconds> youngest_peer{-1, 0}, next_youngest_peer{-1, 0};
5293	
5294	        m_connman.ForEachNode([&](CNode* pnode) {
5295	            if (!pnode->IsBlockOnlyConn() || pnode->fDisconnect) return;
5296	            if (pnode->GetId() > youngest_peer.first) {
5297	                next_youngest_peer = youngest_peer;
5298	                youngest_peer.first = pnode->GetId();
5299	                youngest_peer.second = pnode->m_last_block_time;
5300	            }
5301	        });
5302	        NodeId to_disconnect = youngest_peer.first;
5303	        if (youngest_peer.second > next_youngest_peer.second) {
5304	            // Our newest block-relay-only peer gave us a block more recently;
5305	            // disconnect our second youngest.
5306	            to_disconnect = next_youngest_peer.first;
5307	        }
5308	        m_connman.ForNode(to_disconnect, [&](CNode* pnode) EXCLUSIVE_LOCKS_REQUIRED(::cs_main) {
5309	            AssertLockHeld(::cs_main);
5310	            // Make sure we're not getting a block right now, and that
5311	            // we've been connected long enough for this eviction to happen
5312	            // at all.
5313	            // Note that we only request blocks from a peer if we learn of a
5314	            // valid headers chain with at least as much work as our tip.
5315	            CNodeState *node_state = State(pnode->GetId());
5316	            if (node_state == nullptr ||
5317	                (now - pnode->m_connected >= MINIMUM_CONNECT_TIME && node_state->vBlocksInFlight.empty())) {
5318	                pnode->fDisconnect = true;
5319	                LogDebug(BCLog::NET, "disconnecting extra block-relay-only peer=%d (last block received at time %d)\n",
5320	                         pnode->GetId(), count_seconds(pnode->m_last_block_time));
5321	                return true;
5322	            } else {
5323	                LogDebug(BCLog::NET, "keeping block-relay-only peer=%d chosen for eviction (connect time: %d, blocks_in_flight: %d)\n",
5324	                         pnode->GetId(), TicksSinceEpoch<std::chrono::seconds>(pnode->m_connected), node_state->vBlocksInFlight.size());
5325	            }
5326	            return false;
5327	        });
5328	    }
5329	
5330	    // Check whether we have too many outbound-full-relay peers
5331	    if (m_connman.GetExtraFullOutboundCount() > 0) {
5332	        // If we have more outbound-full-relay peers than we target, disconnect one.
5333	        // Pick the outbound-full-relay peer that least recently announced
5334	        // us a new block, with ties broken by choosing the more recent
5335	        // connection (higher node id)
5336	        // Protect peers from eviction if we don't have another connection
5337	        // to their network, counting both outbound-full-relay and manual peers.
5338	        NodeId worst_peer = -1;
5339	        int64_t oldest_block_announcement = std::numeric_limits<int64_t>::max();
5340	
5341	        m_connman.ForEachNode([&](CNode* pnode) EXCLUSIVE_LOCKS_REQUIRED(::cs_main, m_connman.GetNodesMutex()) {
5342	            AssertLockHeld(::cs_main);
5343	
5344	            // Only consider outbound-full-relay peers that are not already
5345	            // marked for disconnection
5346	            if (!pnode->IsFullOutboundConn() || pnode->fDisconnect) return;
5347	            CNodeState *state = State(pnode->GetId());
5348	            if (state == nullptr) return; // shouldn't be possible, but just in case
5349	            // Don't evict our protected peers
5350	            if (state->m_chain_sync.m_protect) return;
5351	            // If this is the only connection on a particular network that is
5352	            // OUTBOUND_FULL_RELAY or MANUAL, protect it.
5353	            if (!m_connman.MultipleManualOrFullOutboundConns(pnode->addr.GetNetwork())) return;
5354	            if (state->m_last_block_announcement < oldest_block_announcement || (state->m_last_block_announcement == oldest_block_announcement && pnode->GetId() > worst_peer)) {
5355	                worst_peer = pnode->GetId();
5356	                oldest_block_announcement = state->m_last_block_announcement;
5357	            }
5358	        });
5359	        if (worst_peer != -1) {
5360	            bool disconnected = m_connman.ForNode(worst_peer, [&](CNode* pnode) EXCLUSIVE_LOCKS_REQUIRED(::cs_main) {
5361	                AssertLockHeld(::cs_main);
5362	
5363	                // Only disconnect a peer that has been connected to us for
5364	                // some reasonable fraction of our check-frequency, to give
5365	                // it time for new information to have arrived.
5366	                // Also don't disconnect any peer we're trying to download a
5367	                // block from.
5368	                CNodeState &state = *State(pnode->GetId());
5369	                if (now - pnode->m_connected > MINIMUM_CONNECT_TIME && state.vBlocksInFlight.empty()) {
5370	                    LogDebug(BCLog::NET, "disconnecting extra outbound peer=%d (last block announcement received at time %d)\n", pnode->GetId(), oldest_block_announcement);
5371	                    pnode->fDisconnect = true;
5372	                    return true;
5373	                } else {
5374	                    LogDebug(BCLog::NET, "keeping outbound peer=%d chosen for eviction (connect time: %d, blocks_in_flight: %d)\n",
5375	                             pnode->GetId(), TicksSinceEpoch<std::chrono::seconds>(pnode->m_connected), state.vBlocksInFlight.size());
5376	                    return false;
5377	                }
5378	            });
5379	            if (disconnected) {
5380	                // If we disconnected an extra peer, that means we successfully
5381	                // connected to at least one peer after the last time we
