5391	void PeerManagerImpl::CheckForStaleTipAndEvictPeers()
5392	{
5393	    LOCK(cs_main);
5394	
5395	    const auto current_time{NodeClock::now()};
5396	    auto now{GetTime<std::chrono::seconds>()};
5397	
5398	    EvictExtraOutboundPeers(current_time);
5399	
5400	    if (now > m_stale_tip_check_time) {
5401	        // Check whether our tip is stale, and if so, allow using an extra
5402	        // outbound peer
5403	        if (!m_chainman.m_blockman.LoadingBlocks() && m_connman.GetNetworkActive() && m_connman.GetUseAddrmanOutgoing() && TipMayBeStale()) {
5404	            LogInfo("Potential stale tip detected, will try using extra outbound peer (last tip update: %d seconds ago)\n",
5405	                      count_seconds(now - m_last_tip_update.load()));
5406	            m_connman.SetTryNewOutboundPeer(true);
5407	        } else if (m_connman.GetTryNewOutboundPeer()) {
5408	            m_connman.SetTryNewOutboundPeer(false);
5409	        }
5410	        m_stale_tip_check_time = now + STALE_CHECK_INTERVAL;
5411	    }
5412	
5413	    if (!m_initial_sync_finished && CanDirectFetch()) {
5414	        m_connman.StartExtraBlockRelayPeers();
5415	        m_initial_sync_finished = true;
5416	    }
5417	}
