5419	void PeerManagerImpl::MaybeSendPing(CNode& node_to, Peer& peer, NodeClock::time_point now)
5420	{
5421	    if (m_connman.ShouldRunInactivityChecks(node_to, now) &&
5422	        peer.m_ping_nonce_sent &&
5423	        now > peer.m_ping_start.load() + TIMEOUT_INTERVAL)
5424	    {
5425	        // The ping timeout is using mocktime. To disable the check during
5426	        // testing, increase -peertimeout.
5427	        LogDebug(BCLog::NET, "ping timeout: %fs, %s", Ticks<SecondsDouble>(now - peer.m_ping_start.load()), node_to.DisconnectMsg());
5428	        node_to.fDisconnect = true;
5429	        return;
5430	    }
5431	
5432	    bool pingSend = false;
5433	
5434	    if (peer.m_ping_queued) {
5435	        // RPC ping request by user
5436	        pingSend = true;
5437	    }
5438	
5439	    if (peer.m_ping_nonce_sent == 0 && now > peer.m_ping_start.load() + PING_INTERVAL) {
5440	        // Ping automatically sent as a latency probe & keepalive.
5441	        pingSend = true;
5442	    }
5443	
5444	    if (pingSend) {
5445	        uint64_t nonce;
5446	        do {
5447	            nonce = FastRandomContext().rand64();
5448	        } while (nonce == 0);
5449	        peer.m_ping_queued = false;
5450	        peer.m_ping_start = now;
5451	        if (node_to.GetCommonVersion() > BIP0031_VERSION) {
5452	            peer.m_ping_nonce_sent = nonce;
5453	            MakeAndPushMessage(node_to, NetMsgType::PING, nonce);
5454	        } else {
5455	            // Peer is too old to support ping message type with nonce, pong will never arrive.
5456	            peer.m_ping_nonce_sent = 0;
5457	            MakeAndPushMessage(node_to, NetMsgType::PING);
5458	        }
5459	    }
5460	}
