5462	void PeerManagerImpl::MaybeSendAddr(CNode& node, Peer& peer, std::chrono::microseconds current_time)
5463	{
5464	    // Nothing to do for non-address-relay peers
5465	    if (!peer.m_addr_relay_enabled) return;
5466	
5467	    LOCK(peer.m_addr_send_times_mutex);
5468	    // Periodically advertise our local address to the peer.
5469	    if (fListen && !m_chainman.IsInitialBlockDownload() &&
5470	        peer.m_next_local_addr_send < current_time) {
5471	        // If we've sent before, clear the bloom filter for the peer, so that our
5472	        // self-announcement will actually go out.
5473	        // This might be unnecessary if the bloom filter has already rolled
5474	        // over since our last self-announcement, but there is only a small
5475	        // bandwidth cost that we can incur by doing this (which happens
5476	        // once a day on average).
5477	        if (peer.m_next_local_addr_send != 0us) {
5478	            peer.m_addr_known->reset();
5479	        }
5480	        if (std::optional<CService> local_service = GetLocalAddrForPeer(node)) {
5481	            CAddress local_addr{*local_service, peer.m_our_services, Now<NodeSeconds>()};
5482	            if (peer.m_next_local_addr_send == 0us) {
5483	                // Send the initial self-announcement in its own message. This makes sure
5484	                // rate-limiting with limited start-tokens doesn't ignore it if the first
5485	                // message ends up containing multiple addresses.
5486	                if (IsAddrCompatible(peer, local_addr)) {
5487	                    std::vector<CAddress> self_announcement{local_addr};
5488	                    if (peer.m_wants_addrv2) {
5489	                        MakeAndPushMessage(node, NetMsgType::ADDRV2, CAddress::V2_NETWORK(self_announcement));
5490	                    } else {
5491	                        MakeAndPushMessage(node, NetMsgType::ADDR, CAddress::V1_NETWORK(self_announcement));
5492	                    }
5493	                }
5494	            } else {
5495	                // All later self-announcements are sent together with the other addresses.
5496	                PushAddress(peer, local_addr);
5497	            }
5498	        }
5499	        peer.m_next_local_addr_send = current_time + m_rng.rand_exp_duration(AVG_LOCAL_ADDRESS_BROADCAST_INTERVAL);

