5688	bool PeerManagerImpl::SetupAddressRelay(const CNode& node, Peer& peer)
5689	{
5690	    // We don't participate in addr relay with outbound block-relay-only
5691	    // connections to prevent providing adversaries with the additional
5692	    // information of addr traffic to infer the link.
5693	    if (node.IsBlockOnlyConn()) return false;
5694	
5695	    if (!peer.m_addr_relay_enabled.exchange(true)) {
5696	        // During version message processing (non-block-relay-only outbound peers)
5697	        // or on first addr-related message we have received (inbound peers), initialize
5698	        // m_addr_known.
5699	        peer.m_addr_known = std::make_unique<CRollingBloomFilter>(5000, 0.001);
5700	    }
5701	
5702	    return true;
5703	}
