5705	void PeerManagerImpl::ProcessAddrs(std::string_view msg_type, CNode& pfrom, Peer& peer, std::vector<CAddress>&& vAddr, const std::atomic<bool>& interruptMsgProc)
5706	{
5707	    AssertLockNotHeld(m_peer_mutex);
5708	    AssertLockHeld(g_msgproc_mutex);
5709	
5710	    if (!SetupAddressRelay(pfrom, peer)) {
5711	        LogDebug(BCLog::NET, "ignoring %s message from %s peer=%d\n", msg_type, pfrom.ConnectionTypeAsString(), pfrom.GetId());
5712	        return;
5713	    }
5714	
5715	    if (vAddr.size() > MAX_ADDR_TO_SEND)
5716	    {
5717	        Misbehaving(peer, strprintf("%s message size = %u", msg_type, vAddr.size()));
5718	        return;
5719	    }
5720	
5721	    // Store the new addresses
5722	    std::vector<CAddress> vAddrOk;
5723	
5724	    // Update/increment addr rate limiting bucket.
5725	    const auto current_time{NodeClock::now()};
5726	    if (peer.m_addr_token_bucket < MAX_ADDR_PROCESSING_TOKEN_BUCKET) {
5727	        // Don't increment bucket if it's already full
5728	        const auto time_diff{current_time - peer.m_addr_token_timestamp};
5729	        const double increment{std::max(Ticks<SecondsDouble>(time_diff), 0.0) * MAX_ADDR_RATE_PER_SECOND};
5730	        peer.m_addr_token_bucket = std::min<double>(peer.m_addr_token_bucket + increment, MAX_ADDR_PROCESSING_TOKEN_BUCKET);
5731	    }
5732	    peer.m_addr_token_timestamp = current_time;
5733	
5734	    const bool rate_limited = !pfrom.HasPermission(NetPermissionFlags::Addr);
5735	    uint64_t num_proc = 0;
5736	    uint64_t num_rate_limit = 0;
5737	    std::shuffle(vAddr.begin(), vAddr.end(), m_rng);
5738	    for (CAddress& addr : vAddr)
5739	    {
5740	        if (interruptMsgProc)
5741	            return;
5742	
5743	        // Apply rate limiting.
5744	        if (peer.m_addr_token_bucket < 1.0) {
5745	            if (rate_limited) {
5746	                ++num_rate_limit;
5747	                continue;
5748	            }
5749	        } else {
5750	            peer.m_addr_token_bucket -= 1.0;
5751	        }
5752	        // We only bother storing full nodes, though this may include
5753	        // things which we would not make an outbound connection to, in
5754	        // part because we may make feeler connections to them.
5755	        if (!MayHaveUsefulAddressDB(addr.nServices) && !HasAllDesirableServiceFlags(addr.nServices))
5756	            continue;
5757	
5758	        if (addr.nTime <= NodeSeconds{100000000s} || addr.nTime > current_time + 10min) {
5759	            addr.nTime = std::chrono::time_point_cast<std::chrono::seconds>(current_time - 5 * 24h);
5760	        }
5761	        AddAddressKnown(peer, addr);
5762	        if (m_banman && (m_banman->IsDiscouraged(addr) || m_banman->IsBanned(addr))) {
5763	            // Do not process banned/discouraged addresses beyond remembering we received them
5764	            continue;
5765	        }
5766	        ++num_proc;
5767	        const bool reachable{g_reachable_nets.Contains(addr)};
5768	        if (addr.nTime > current_time - 10min && !peer.m_getaddr_sent && vAddr.size() <= 10 && addr.IsRoutable()) {
5769	            // Relay to a limited number of other nodes
5770	            RelayAddress(pfrom.GetId(), addr, reachable);
5771	        }
5772	        // Do not store addresses outside our network
5773	        if (reachable) {
5774	            vAddrOk.push_back(addr);
5775	        }
5776	    }
5777	    peer.m_addr_processed += num_proc;
5778	    peer.m_addr_rate_limited += num_rate_limit;
5779	    LogDebug(BCLog::NET, "Received addr: %u addresses (%u processed, %u rate-limited) from peer=%d\n",
5780	             vAddr.size(), num_proc, num_rate_limit, pfrom.GetId());
5781	
5782	    m_addrman.Add(vAddrOk, pfrom.addr, /*time_penalty=*/2h);
5783	    if (vAddr.size() < 1000) peer.m_getaddr_sent = false;
5784	
5785	    // AddrFetch: Require multiple addresses to avoid disconnecting on self-announcements
5786	    if (pfrom.IsAddrFetchConn() && vAddr.size() > 1) {
5787	        LogDebug(BCLog::NET, "addrfetch connection completed, %s", pfrom.DisconnectMsg());
5788	        pfrom.fDisconnect = true;
5789	    }
5790	}
