5792	bool PeerManagerImpl::SendMessages(CNode& node)
5793	{
5794	    AssertLockNotHeld(m_tx_download_mutex);
5795	    AssertLockHeld(g_msgproc_mutex);
5796	
5797	    PeerRef maybe_peer{GetPeerRef(node.GetId())};
5798	    if (!maybe_peer) return false;
5799	    Peer& peer{*maybe_peer};
5800	    const Consensus::Params& consensusParams = m_chainparams.GetConsensus();
5801	
5802	    // We must call MaybeDiscourageAndDisconnect first, to ensure that we'll
5803	    // disconnect misbehaving peers even before the version handshake is complete.
5804	    if (MaybeDiscourageAndDisconnect(node, peer)) return true;
5805	
5806	    // Initiate version handshake for outbound connections
5807	    if (!node.IsInboundConn() && !peer.m_outbound_version_message_sent) {
5808	        PushNodeVersion(node, peer);
5809	        peer.m_outbound_version_message_sent = true;
5810	    }
5811	
5812	    // Don't send anything until the version handshake is complete
5813	    if (!node.fSuccessfullyConnected || node.fDisconnect)
5814	        return true;
5815	
5816	    const auto now{NodeClock::now()};
5817	    const auto current_time{GetTime<std::chrono::microseconds>()};
5818	
5819	    // The logic below does not apply to private broadcast peers, so skip it.
5820	    // Also in CConnman::PushMessage() we make sure that unwanted messages are
5821	    // not sent. This here is just an optimization.
5822	    if (node.IsPrivateBroadcastConn()) {
5823	        if (node.m_connected + PRIVATE_BROADCAST_MAX_CONNECTION_LIFETIME < now) {
5824	            LogDebug(BCLog::PRIVBROADCAST, "Disconnecting: did not complete the transaction send within %d seconds, %s",
5825	                     count_seconds(PRIVATE_BROADCAST_MAX_CONNECTION_LIFETIME), node.LogPeer());
5826	            node.fDisconnect = true;
5827	        }
5828	        return true;
5829	    }
5830	
5831	    if (node.IsAddrFetchConn() && now - node.m_connected > 10 * AVG_ADDRESS_BROADCAST_INTERVAL) {
5832	        LogDebug(BCLog::NET, "addrfetch connection timeout, %s", node.DisconnectMsg());
5833	        node.fDisconnect = true;
5834	        return true;
5835	    }
5836	
5837	    MaybeSendPing(node, peer, now);
5838	
5839	    // MaybeSendPing may have marked peer for disconnection
5840	    if (node.fDisconnect) return true;
5841	
5842	    MaybeSendAddr(node, peer, current_time);
5843	
5844	    MaybeSendSendHeaders(node, peer);
5845	
5846	    {
5847	        LOCK(cs_main);
5848	
5849	        CNodeState &state = *State(node.GetId());
5850	
5851	        // Start block sync
5852	        if (m_chainman.m_best_header == nullptr) {
5853	            m_chainman.m_best_header = m_chainman.ActiveChain().Tip();
5854	        }
5855	
5856	        // Determine whether we might try initial headers sync or parallel
5857	        // block download from this peer -- this mostly affects behavior while
5858	        // in IBD (once out of IBD, we sync from all peers).
5859	        bool sync_blocks_and_headers_from_peer = false;
5860	        if (state.fPreferredDownload) {
5861	            sync_blocks_and_headers_from_peer = true;
5862	        } else if (CanServeBlocks(peer) && !node.IsAddrFetchConn()) {
5863	            // Typically this is an inbound peer. If we don't have any outbound
5864	            // peers, or if we aren't downloading any blocks from such peers,
5865	            // then allow block downloads from this peer, too.
5866	            // We prefer downloading blocks from outbound peers to avoid
5867	            // putting undue load on (say) some home user who is just making
5868	            // outbound connections to the network, but if our only source of
5869	            // the latest blocks is from an inbound peer, we have to be sure to
5870	            // eventually download it (and not just wait indefinitely for an
5871	            // outbound peer to have it).
5872	            if (m_num_preferred_download_peers == 0 || mapBlocksInFlight.empty()) {
5873	                sync_blocks_and_headers_from_peer = true;
5874	            }
5875	        }
5876	
5877	        if (!state.fSyncStarted && CanServeBlocks(peer) && !m_chainman.m_blockman.LoadingBlocks()) {
5878	            // Only actively request headers from a single peer, unless we're close to today.
5879	            if ((nSyncStarted == 0 && sync_blocks_and_headers_from_peer) || m_chainman.m_best_header->Time() > NodeClock::now() - 24h) {
5880	                const CBlockIndex* pindexStart = m_chainman.m_best_header;
5881	                /* If possible, start at the block preceding the currently
5882	                   best known header.  This ensures that we always get a
5883	                   non-empty list of headers back as long as the peer
5884	                   is up-to-date.  With a non-empty response, we can initialise
5885	                   the peer's known best block.  This wouldn't be possible
5886	                   if we requested starting at m_chainman.m_best_header and
5887	                   got back an empty response.  */
5888	                if (pindexStart->pprev)
5889	                    pindexStart = pindexStart->pprev;
5890	                if (MaybeSendGetHeaders(node, GetLocator(pindexStart), peer)) {
5891	                    LogDebug(BCLog::NET, "initial getheaders (%d) to peer=%d", pindexStart->nHeight, node.GetId());
5892	
5893	                    state.fSyncStarted = true;
5894	                    peer.m_headers_sync_timeout = current_time + HEADERS_DOWNLOAD_TIMEOUT_BASE +
5895	                        (
5896	                         // Convert HEADERS_DOWNLOAD_TIMEOUT_PER_HEADER to microseconds before scaling
5897	                         // to maintain precision
5898	                         std::chrono::microseconds{HEADERS_DOWNLOAD_TIMEOUT_PER_HEADER} *
5899	                         Ticks<std::chrono::seconds>(NodeClock::now() - m_chainman.m_best_header->Time()) / consensusParams.nPowTargetSpacing
5900	                        );
5901	                    nSyncStarted++;
5902	                }
5903	            }
5904	        }
5905	
5906	        //
5907	        // Try sending block announcements via headers
5908	        //
5909	        {
5910	            // If we have no more than MAX_BLOCKS_TO_ANNOUNCE in our
5911	            // list of block hashes we're relaying, and our peer wants
5912	            // headers announcements, then find the first header
5913	            // not yet known to our peer but would connect, and send.
5914	            // If no header would connect, or if we have too many
5915	            // blocks, or if the peer doesn't want headers, just
5916	            // add all to the inv queue.
5917	            LOCK(peer.m_block_inv_mutex);
5918	            std::vector<CBlock> vHeaders;
5919	            bool fRevertToInv = ((!peer.m_prefers_headers &&
5920	                                 (!state.m_requested_hb_cmpctblocks || peer.m_blocks_for_headers_relay.size() > 1)) ||
5921	                                 peer.m_blocks_for_headers_relay.size() > MAX_BLOCKS_TO_ANNOUNCE);
5922	            const CBlockIndex *pBestIndex = nullptr; // last header queued for delivery
5923	            ProcessBlockAvailability(node.GetId()); // ensure pindexBestKnownBlock is up-to-date
5924	
5925	            if (!fRevertToInv) {
5926	                bool fFoundStartingHeader = false;
5927	                // Try to find first header that our peer doesn't have, and
5928	                // then send all headers past that one.  If we come across any
5929	                // headers that aren't on m_chainman.ActiveChain(), give up.
5930	                for (const uint256& hash : peer.m_blocks_for_headers_relay) {
5931	                    const CBlockIndex* pindex = m_chainman.m_blockman.LookupBlockIndex(hash);
5932	                    assert(pindex);
5933	                    if (m_chainman.ActiveChain()[pindex->nHeight] != pindex) {
5934	                        // Bail out if we reorged away from this block
5935	                        fRevertToInv = true;
5936	                        break;
5937	                    }
5938	                    if (pBestIndex != nullptr && pindex->pprev != pBestIndex) {
5939	                        // This means that the list of blocks to announce don't
5940	                        // connect to each other.
5941	                        // This shouldn't really be possible to hit during
5942	                        // regular operation (because reorgs should take us to
5943	                        // a chain that has some block not on the prior chain,
5944	                        // which should be caught by the prior check), but one
5945	                        // way this could happen is by using invalidateblock /
5946	                        // reconsiderblock repeatedly on the tip, causing it to
5947	                        // be added multiple times to m_blocks_for_headers_relay.
5948	                        // Robustly deal with this rare situation by reverting
5949	                        // to an inv.
5950	                        fRevertToInv = true;
5951	                        break;
5952	                    }
5953	                    pBestIndex = pindex;
5954	                    if (fFoundStartingHeader) {
5955	                        // add this to the headers message
5956	                        vHeaders.emplace_back(pindex->GetBlockHeader());
5957	                    } else if (PeerHasHeader(&state, pindex)) {
5958	                        continue; // keep looking for the first new block
5959	                    } else if (pindex->pprev == nullptr || PeerHasHeader(&state, pindex->pprev)) {
5960	                        // Peer doesn't have this header but they do have the prior one.
5961	                        // Start sending headers.
5962	                        fFoundStartingHeader = true;
5963	                        vHeaders.emplace_back(pindex->GetBlockHeader());
5964	                    } else {
5965	                        // Peer doesn't have this header or the prior one -- nothing will
5966	                        // connect, so bail out.
5967	                        fRevertToInv = true;
5968	                        break;
5969	                    }
5970	                }
5971	            }
5972	            if (!fRevertToInv && !vHeaders.empty()) {
5973	                if (vHeaders.size() == 1 && state.m_requested_hb_cmpctblocks) {
5974	                    // We only send up to 1 block as header-and-ids, as otherwise
5975	                    // probably means we're doing an initial-ish-sync or they're slow
5976	                    LogDebug(BCLog::NET, "%s sending header-and-ids %s to peer=%d\n", __func__,
5977	                            vHeaders.front().GetHash().ToString(), node.GetId());
5978	
