2989	void PeerManagerImpl::ProcessHeadersMessage(CNode& pfrom, Peer& peer,
2990	                                            std::vector<CBlockHeader>&& headers,
2991	                                            bool via_compact_block)
2992	{
2993	    size_t nCount = headers.size();
2994	
2995	    if (nCount == 0) {
2996	        // Nothing interesting. Stop asking this peers for more headers.
2997	        // If we were in the middle of headers sync, receiving an empty headers
2998	        // message suggests that the peer suddenly has nothing to give us
2999	        // (perhaps it reorged to our chain). Clear download state for this peer.
3000	        LOCK(peer.m_headers_sync_mutex);
3001	        if (peer.m_headers_sync) {
3002	            peer.m_headers_sync.reset(nullptr);
3003	            LOCK(m_headers_presync_mutex);
3004	            m_headers_presync_stats.erase(pfrom.GetId());
3005	        }
3006	        // A headers message with no headers cannot be an announcement, so assume
3007	        // it is a response to our last getheaders request, if there is one.
3008	        peer.m_last_getheaders_timestamp = {};
3009	        return;
3010	    }
3011	
3012	    // Before we do any processing, make sure these pass basic sanity checks.
3013	    // We'll rely on headers having valid proof-of-work further down, as an
3014	    // anti-DoS criteria (note: this check is required before passing any
3015	    // headers into HeadersSyncState).
3016	    if (!CheckHeadersPoW(headers, peer)) {
3017	        // Misbehaving() calls are handled within CheckHeadersPoW(), so we can
3018	        // just return. (Note that even if a header is announced via compact
3019	        // block, the header itself should be valid, so this type of error can
3020	        // always be punished.)
3021	        return;
3022	    }
3023	
3024	    const CBlockIndex *pindexLast = nullptr;
3025	
3026	    // We'll set already_validated_work to true if these headers are
3027	    // successfully processed as part of a low-work headers sync in progress
3028	    // (either in PRESYNC or REDOWNLOAD phase).
3029	    // If true, this will mean that any headers returned to us (ie during
3030	    // REDOWNLOAD) can be validated without further anti-DoS checks.
3031	    bool already_validated_work = false;
3032	
3033	    // If we're in the middle of headers sync, let it do its magic.
3034	    bool have_headers_sync = false;
3035	    {
3036	        LOCK(peer.m_headers_sync_mutex);
3037	
3038	        already_validated_work = IsContinuationOfLowWorkHeadersSync(peer, pfrom, headers);
3039	
3040	        // The headers we passed in may have been:
3041	        // - untouched, perhaps if no headers-sync was in progress, or some
3042	        //   failure occurred
3043	        // - erased, such as if the headers were successfully processed and no
3044	        //   additional headers processing needs to take place (such as if we
3045	        //   are still in PRESYNC)
3046	        // - replaced with headers that are now ready for validation, such as
3047	        //   during the REDOWNLOAD phase of a low-work headers sync.
3048	        // So just check whether we still have headers that we need to process,
3049	        // or not.
3050	        if (headers.empty()) {
3051	            return;
3052	        }
3053	
3054	        have_headers_sync = !!peer.m_headers_sync;
3055	    }
3056	
3057	    // Do these headers connect to something in our block index?
3058	    const CBlockIndex *chain_start_header{WITH_LOCK(::cs_main, return m_chainman.m_blockman.LookupBlockIndex(headers[0].hashPrevBlock))};
3059	    bool headers_connect_blockindex{chain_start_header != nullptr};
3060	
3061	    if (!headers_connect_blockindex) {
3062	        // This could be a BIP 130 block announcement, use
3063	        // special logic for handling headers that don't connect, as this
3064	        // could be benign.
3065	        HandleUnconnectingHeaders(pfrom, peer, headers);
3066	        return;
3067	    }
3068	
3069	    // If headers connect, assume that this is in response to any outstanding getheaders
3070	    // request we may have sent, and clear out the time of our last request. Non-connecting
3071	    // headers cannot be a response to a getheaders request.
3072	    peer.m_last_getheaders_timestamp = {};
3073	
3074	    // If the headers we received are already in memory and an ancestor of
3075	    // m_best_header or our tip, skip anti-DoS checks. These headers will not
3076	    // use any more memory (and we are not leaking information that could be
3077	    // used to fingerprint us).
3078	    const CBlockIndex *last_received_header{nullptr};
3079	    {
3080	        LOCK(cs_main);
3081	        last_received_header = m_chainman.m_blockman.LookupBlockIndex(headers.back().GetHash());
3082	        already_validated_work = already_validated_work || IsAncestorOfBestHeaderOrTip(last_received_header);
3083	    }
3084	
3085	    // If our peer has NetPermissionFlags::NoBan privileges, then bypass our
3086	    // anti-DoS logic (this saves bandwidth when we connect to a trusted peer
3087	    // on startup).
3088	    if (pfrom.HasPermission(NetPermissionFlags::NoBan)) {
3089	        already_validated_work = true;
3090	    }
3091	
3092	    // At this point, the headers connect to something in our block index.
3093	    // Do anti-DoS checks to determine if we should process or store for later
3094	    // processing.
3095	    if (!already_validated_work && TryLowWorkHeadersSync(peer, pfrom,
3096	                                                         *chain_start_header, headers)) {
3097	        // If we successfully started a low-work headers sync, then there
3098	        // should be no headers to process any further.
3099	        Assume(headers.empty());

2000	        setBlockIndexCandidates.erase(pindex);
2001	        InvalidChainFound(pindex);
2002	    }
2003	}
