2663	arith_uint256 PeerManagerImpl::GetAntiDoSWorkThreshold()
2664	{
2665	    arith_uint256 near_chaintip_work = 0;
2666	    LOCK(cs_main);
2667	    if (m_chainman.ActiveChain().Tip() != nullptr) {
2668	        const CBlockIndex *tip = m_chainman.ActiveChain().Tip();
2669	        // Use a 144 block buffer, so that we'll accept headers that fork from
2670	        // near our tip.
2671	        near_chaintip_work = tip->nChainWork - std::min<arith_uint256>(144*GetBlockProof(*tip), tip->nChainWork);
2672	    }
2673	    return std::max(near_chaintip_work, m_chainman.MinimumChainWork());
2674	}
