2463	    if (pblock) {
2464	        if (inv.IsMsgBlk()) {
2465	            MakeAndPushMessage(pfrom, NetMsgType::BLOCK, TX_NO_WITNESS(*pblock));
2466	        } else if (inv.IsMsgWitnessBlk()) {
2467	            MakeAndPushMessage(pfrom, NetMsgType::BLOCK, TX_WITH_WITNESS(*pblock));
2468	        } else if (inv.IsMsgFilteredBlk()) {
2469	            bool sendMerkleBlock = false;
2470	            CMerkleBlock merkleBlock;
2471	            if (auto tx_relay = peer.GetTxRelay(); tx_relay != nullptr) {
2472	                LOCK(tx_relay->m_bloom_filter_mutex);
2473	                if (tx_relay->m_bloom_filter) {
2474	                    sendMerkleBlock = true;
2475	                    merkleBlock = CMerkleBlock(*pblock, *tx_relay->m_bloom_filter);
2476	                }
2477	            }
2478	            if (sendMerkleBlock) {
2479	                MakeAndPushMessage(pfrom, NetMsgType::MERKLEBLOCK, merkleBlock);
2480	                // CMerkleBlock just contains hashes, so also push any transactions in the block the client did not see
2481	                // This avoids hurting performance by pointlessly requiring a round-trip
2482	                // Note that there is currently no way for a node to request any single transactions we didn't send here -
2483	                // they must either disconnect and retry or request the full block.
2484	                // Thus, the protocol spec specified allows for us to provide duplicate txn here,
2485	                // however we MUST always provide at least what the remote peer needs
2486	                for (const auto& [tx_idx, _] : merkleBlock.vMatchedTxn)
2487	                    MakeAndPushMessage(pfrom, NetMsgType::TX, TX_NO_WITNESS(*pblock->vtx[tx_idx]));
2488	            }
2489	            // else
2490	            // no response
2491	        } else if (inv.IsMsgCmpctBlk()) {
2492	            // If a peer is asking for old blocks, we're almost guaranteed
2493	            // they won't have a useful mempool to match against a compact block,
2494	            // and we don't feel like constructing the object for them, so
2495	            // instead we respond with the full, non-compact block.
2496	            if (can_direct_fetch && pindex->nHeight >= tip->nHeight - MAX_CMPCTBLOCK_DEPTH) {
2497	                if (a_recent_compact_block && a_recent_compact_block->header.GetHash() == inv.hash) {
2498	                    MakeAndPushMessage(pfrom, NetMsgType::CMPCTBLOCK, *a_recent_compact_block);
2499	                } else {
2500	                    CBlockHeaderAndShortTxIDs cmpctblock{*pblock, m_rng.rand64()};
2501	                    MakeAndPushMessage(pfrom, NetMsgType::CMPCTBLOCK, cmpctblock);
2502	                }
2503	            } else {
2504	                MakeAndPushMessage(pfrom, NetMsgType::BLOCK, TX_WITH_WITNESS(*pblock));
2505	            }
2506	        }
2507	    }
2508	
2509	    {
2510	        LOCK(peer.m_block_inv_mutex);
2511	        // Trigger the peer node to send a getblocks request for the next batch of inventory
2512	        if (inv.hash == peer.m_continuation_block) {
2513	            // Send immediately. This must send even if redundant,
2514	            // and we want it right after the last block so they don't
2515	            // wait for other stuff first.
2516	            std::vector<CInv> vInv;
2517	            vInv.emplace_back(MSG_BLOCK, tip->GetBlockHash());
2518	            MakeAndPushMessage(pfrom, NetMsgType::INV, vInv);
2519	            peer.m_continuation_block.SetNull();
2520	        }
2521	    }
2522	}
