2642	        LogDebug(BCLog::CMPCTBLOCK, "Peer %d sent us a GETBLOCKTXN for block %s, sending a BLOCKTXN with %u txns. (%u bytes)\n", pfrom.GetId(), block.GetHash().ToString(), resp.txn.size(), tx_requested_size);
2643	    }
2644	    MakeAndPushMessage(pfrom, NetMsgType::BLOCKTXN, resp);
2645	}
