3706	void Chainstate::SetBlockFailureFlags(CBlockIndex* invalid_block)
3707	{
3708	    AssertLockHeld(cs_main);
3709	
3710	    for (auto& [_, block_index] : m_blockman.m_block_index) {
3711	        if (invalid_block != &block_index && block_index.GetAncestor(invalid_block->nHeight) == invalid_block) {
3712	            block_index.nStatus |= BLOCK_FAILED_VALID;
3713	            m_blockman.m_dirty_blockindex.insert(&block_index);
3714	        }
3715	    }
