3771	/** Mark a block as having its data received and checked (up to BLOCK_VALID_TRANSACTIONS). */
3772	void ChainstateManager::ReceivedBlockTransactions(const CBlock& block, CBlockIndex* pindexNew, const FlatFilePos& pos)
3773	{
3774	    AssertLockHeld(cs_main);
3775	    pindexNew->nTx = block.vtx.size();
3776	    // Typically m_chain_tx_count will be 0 at this point, but it can be nonzero if this
3777	    // is a pruned block which is being downloaded again, or if this is an
3778	    // assumeutxo snapshot block which has a hardcoded m_chain_tx_count value from the
3779	    // snapshot metadata. If the pindex is not the snapshot block and the
3780	    // m_chain_tx_count value is not zero, assert that value is actually correct.
3781	    auto prev_tx_sum = [](CBlockIndex& block) { return block.nTx + (block.pprev ? block.pprev->m_chain_tx_count : 0); };
3782	    if (!Assume(pindexNew->m_chain_tx_count == 0 || pindexNew->m_chain_tx_count == prev_tx_sum(*pindexNew) ||
3783	                std::ranges::any_of(m_chainstates, [&](const auto& cs) EXCLUSIVE_LOCKS_REQUIRED(cs_main) { return cs->SnapshotBase() == pindexNew; }))) {
3784	        LogWarning("Internal bug detected: block %d has unexpected m_chain_tx_count %i that should be %i (%s %s). Please report this issue here: %s\n",
3785	            pindexNew->nHeight, pindexNew->m_chain_tx_count, prev_tx_sum(*pindexNew), CLIENT_NAME, FormatFullVersion(), CLIENT_BUGREPORT);
3786	        pindexNew->m_chain_tx_count = 0;
3787	    }
3788	    pindexNew->nFile = pos.nFile;
3789	    pindexNew->nDataPos = pos.nPos;
3790	    pindexNew->nUndoPos = 0;
3791	    pindexNew->nStatus |= BLOCK_HAVE_DATA;
3792	    if (DeploymentActiveAt(*pindexNew, *this, Consensus::DEPLOYMENT_SEGWIT)) {
3793	        pindexNew->nStatus |= BLOCK_OPT_WITNESS;
3794	    }
3795	    pindexNew->RaiseValidity(BLOCK_VALID_TRANSACTIONS);
3796	    m_blockman.m_dirty_blockindex.insert(pindexNew);
3797	
3798	    if (pindexNew->pprev == nullptr || pindexNew->pprev->HaveNumChainTxs()) {
3799	        // If pindexNew is the genesis block or all parents are BLOCK_VALID_TRANSACTIONS.
3800	        std::deque<CBlockIndex*> queue;
3801	        queue.push_back(pindexNew);
3802	
3803	        // Recursively process any descendant blocks that now may be eligible to be connected.
3804	        while (!queue.empty()) {
3805	            CBlockIndex *pindex = queue.front();
3806	            queue.pop_front();
3807	            // Before setting m_chain_tx_count, assert that it is 0 or already set to
3808	            // the correct value. This assert will fail after receiving the
3809	            // assumeutxo snapshot block if assumeutxo snapshot metadata has an
3810	            // incorrect hardcoded AssumeutxoData::m_chain_tx_count value.
3811	            if (!Assume(pindex->m_chain_tx_count == 0 || pindex->m_chain_tx_count == prev_tx_sum(*pindex))) {
3812	                LogWarning("Internal bug detected: block %d has unexpected m_chain_tx_count %i that should be %i (%s %s). Please report this issue here: %s\n",
3813	                   pindex->nHeight, pindex->m_chain_tx_count, prev_tx_sum(*pindex), CLIENT_NAME, FormatFullVersion(), CLIENT_BUGREPORT);
3814	            }
3815	            pindex->m_chain_tx_count = prev_tx_sum(*pindex);
3816	            pindex->nSequenceId = nBlockSequenceId++;
3817	            for (const auto& c : m_chainstates) {
3818	                c->TryAddBlockIndexCandidate(pindex);
3819	            }
3820	            std::pair<std::multimap<CBlockIndex*, CBlockIndex*>::iterator, std::multimap<CBlockIndex*, CBlockIndex*>::iterator> range = m_blockman.m_blocks_unlinked.equal_range(pindex);
3821	            while (range.first != range.second) {
3822	                std::multimap<CBlockIndex*, CBlockIndex*>::iterator it = range.first;
3823	                queue.push_back(it->second);
3824	                range.first++;
3825	                m_blockman.m_blocks_unlinked.erase(it);
3826	            }
3827	        }
3828	    } else {
3829	        if (pindexNew->pprev && pindexNew->pprev->IsValid(BLOCK_VALID_TREE)) {
3830	            m_blockman.m_blocks_unlinked.insert(std::make_pair(pindexNew->pprev, pindexNew));
3831	        }
3832	    }
3833	}
