3844	static bool CheckMerkleRoot(const CBlock& block, BlockValidationState& state)
3845	{
3846	    if (block.m_checked_merkle_root) return true;
3847	
3848	    bool mutated;
3849	    uint256 merkle_root = BlockMerkleRoot(block, &mutated);
3850	    if (block.hashMerkleRoot != merkle_root) {
3851	        return state.Invalid(
3852	            /*result=*/BlockValidationResult::BLOCK_MUTATED,
3853	            /*reject_reason=*/"bad-txnmrklroot",
3854	            /*debug_message=*/"hashMerkleRoot mismatch");
3855	    }
3856	
3857	    // Check for merkle tree malleability (CVE-2012-2459): repeating sequences
3858	    // of transactions in a block without affecting the merkle root of a block,
3859	    // while still invalidating it.
3860	    if (mutated) {
3861	        return state.Invalid(
3862	            /*result=*/BlockValidationResult::BLOCK_MUTATED,
3863	            /*reject_reason=*/"bad-txns-duplicate",
3864	            /*debug_message=*/"duplicate transaction");
3865	    }
3866	
3867	    block.m_checked_merkle_root = true;
3868	    return true;
3869	}
