3871	/** CheckWitnessMalleation performs checks for block malleation with regard to
3872	 * its witnesses.
3873	 *
3874	 * Note: If the witness commitment is expected (i.e. `expect_witness_commitment
3875	 * = true`), then the block is required to have at least one transaction and the
3876	 * first transaction needs to have at least one input. */
3877	static bool CheckWitnessMalleation(const CBlock& block, bool expect_witness_commitment, BlockValidationState& state)
3878	{
3879	    if (expect_witness_commitment) {
3880	        if (block.m_checked_witness_commitment) return true;
3881	
3882	        int commitpos = GetWitnessCommitmentIndex(block);
3883	        if (commitpos != NO_WITNESS_COMMITMENT) {
3884	            assert(!block.vtx.empty() && !block.vtx[0]->vin.empty());
3885	            const auto& witness_stack{block.vtx[0]->vin[0].scriptWitness.stack};
3886	
3887	            if (witness_stack.size() != 1 || witness_stack[0].size() != 32) {
3888	                return state.Invalid(
3889	                    /*result=*/BlockValidationResult::BLOCK_MUTATED,
3890	                    /*reject_reason=*/"bad-witness-nonce-size",
3891	                    /*debug_message=*/strprintf("%s : invalid witness reserved value size", __func__));
3892	            }
3893	
3894	            // The malleation check is ignored; as the transaction tree itself
3895	            // already does not permit it, it is impossible to trigger in the
3896	            // witness tree.
3897	            uint256 hash_witness = BlockWitnessMerkleRoot(block);
3898	
3899	            CHash256().Write(hash_witness).Write(witness_stack[0]).Finalize(hash_witness);

