3230	        // a few blocks along the way.
3231	        int nTargetHeight = std::min(nHeight + 32, index_most_work.nHeight);
3232	        vpindexToConnect.clear();
3233	        vpindexToConnect.reserve(nTargetHeight - nHeight);
