4248	// Exposed wrapper for AcceptBlockHeader
4249	bool ChainstateManager::ProcessNewBlockHeaders(std::span<const CBlockHeader> headers, bool min_pow_checked, BlockValidationState& state, const CBlockIndex** ppindex)
4250	{
4251	    AssertLockNotHeld(cs_main);
4252	    {
4253	        LOCK(cs_main);
4254	        for (const CBlockHeader& header : headers) {
4255	            CBlockIndex *pindex = nullptr; // Use a temp pindex instead of ppindex to avoid a const_cast
4256	            bool accepted{AcceptBlockHeader(header, state, &pindex, min_pow_checked)};
4257	            CheckBlockIndex();
4258	
4259	            if (!accepted) {
4260	                return false;
4261	            }
4262	            if (ppindex) {
4263	                *ppindex = pindex;
4264	            }
4265	        }
4266	    }
4267	    if (NotifyHeaderTip()) {
4268	        if (IsInitialBlockDownload() && ppindex && *ppindex) {
4269	            const CBlockIndex& last_accepted{**ppindex};
4270	            int64_t blocks_left{(NodeClock::now() - last_accepted.Time()) / GetConsensus().PowTargetSpacing()};
4271	            blocks_left = std::max<int64_t>(0, blocks_left);
4272	            const double progress{100.0 * last_accepted.nHeight / (last_accepted.nHeight + blocks_left)};
4273	            LogInfo("Synchronizing blockheaders, height: %d (~%.2f%%)\n", last_accepted.nHeight, progress);
4274	        }
4275	    }
4276	    return true;
4277	}
