4279	void ChainstateManager::ReportHeadersPresync(int64_t height, int64_t timestamp)
4280	{
4281	    AssertLockNotHeld(GetMutex());
4282	    {
4283	        LOCK(GetMutex());
4284	        // Don't report headers presync progress if we already have a post-minchainwork header chain.
4285	        // This means we lose reporting for potentially legitimate, but unlikely, deep reorgs, but
4286	        // prevent attackers that spam low-work headers from filling our logs.
4287	        if (m_best_header->nChainWork >= UintToArith256(GetConsensus().nMinimumChainWork)) return;
4288	        // Rate limit headers presync updates to 4 per second, as these are not subject to DoS
4289	        // protection.
4290	        auto now = MockableSteadyClock::now();
4291	        if (now < m_last_presync_update + std::chrono::milliseconds{250}) return;
4292	        m_last_presync_update = now;
4293	    }
4294	    bool initial_download = IsInitialBlockDownload();
4295	    GetNotifications().headerTip(GetSynchronizationState(initial_download, m_blockman.m_blockfiles_indexed), height, timestamp, /*presync=*/true);
4296	    if (initial_download) {
4297	        int64_t blocks_left{(NodeClock::now() - NodeSeconds{std::chrono::seconds{timestamp}}) / GetConsensus().PowTargetSpacing()};
4298	        blocks_left = std::max<int64_t>(0, blocks_left);
4299	        const double progress{100.0 * height / (height + blocks_left)};
4300	        LogInfo("Pre-synchronizing blockheaders, height: %d (~%.2f%%)\n", height, progress);
4301	    }
4302	}
