4618	VerifyDBResult CVerifyDB::VerifyDB(
4619	    Chainstate& chainstate,
4620	    const Consensus::Params& consensus_params,
4621	    CCoinsView& coinsview,
4622	    int nCheckLevel, int nCheckDepth)
4623	{
4624	    AssertLockHeld(cs_main);
4625	
4626	    if (chainstate.m_chain.Tip() == nullptr || chainstate.m_chain.Tip()->pprev == nullptr) {
4627	        return VerifyDBResult::SUCCESS;
4628	    }
4629	
4630	    // Verify blocks in the best chain
4631	    if (nCheckDepth <= 0 || nCheckDepth > chainstate.m_chain.Height()) {
4632	        nCheckDepth = chainstate.m_chain.Height();
4633	    }
4634	    nCheckLevel = std::max(0, std::min(4, nCheckLevel));
4635	    LogInfo("Verifying last %i blocks at level %i", nCheckDepth, nCheckLevel);
4636	    CCoinsViewCache coins(&coinsview);
4637	    CBlockIndex* pindex;
4638	    CBlockIndex* pindexFailure = nullptr;
4639	    int nGoodTransactions = 0;
4640	    BlockValidationState state;
4641	    int reportDone = 0;
4642	    bool skipped_no_block_data{false};
4643	    bool skipped_l3_checks{false};
4644	    LogInfo("Verification progress: 0%%");
4645	
4646	    const bool is_snapshot_cs{chainstate.m_from_snapshot_blockhash};
4647	
4648	    for (pindex = chainstate.m_chain.Tip(); pindex && pindex->pprev; pindex = pindex->pprev) {
4649	        const int percentageDone = std::max(1, std::min(99, (int)(((double)(chainstate.m_chain.Height() - pindex->nHeight)) / (double)nCheckDepth * (nCheckLevel >= 4 ? 50 : 100))));
4650	        if (reportDone < percentageDone / 10) {
4651	            // report every 10% step
4652	            LogInfo("Verification progress: %d%%", percentageDone);
4653	            reportDone = percentageDone / 10;
4654	        }
4655	        m_notifications.progress(_("Verifying blocks…"), percentageDone, false);
4656	        if (pindex->nHeight <= chainstate.m_chain.Height() - nCheckDepth) {
4657	            break;
4658	        }
4659	        if ((chainstate.m_blockman.IsPruneMode() || is_snapshot_cs) && !(pindex->nStatus & BLOCK_HAVE_DATA)) {
4660	            // If pruning or running under an assumeutxo snapshot, only go
4661	            // back as far as we have data.
4662	            LogInfo("Block verification stopping at height %d (no data). This could be due to pruning or use of an assumeutxo snapshot.", pindex->nHeight);
4663	            skipped_no_block_data = true;
4664	            break;
4665	        }
4666	        CBlock block;
4667	        // check level 0: read from disk
4668	        if (!chainstate.m_blockman.ReadBlock(block, *pindex)) {
4669	            LogError("Verification error: ReadBlock failed at %d, hash=%s", pindex->nHeight, pindex->GetBlockHash().ToString());
4670	            return VerifyDBResult::CORRUPTED_BLOCK_DB;
4671	        }
4672	        // check level 1: verify block validity
4673	        if (nCheckLevel >= 1 && !CheckBlock(block, state, consensus_params)) {
4674	            LogError("Verification error: found bad block at %d, hash=%s (%s)",
4675	                      pindex->nHeight, pindex->GetBlockHash().ToString(), state.ToString());
4676	            return VerifyDBResult::CORRUPTED_BLOCK_DB;
4677	        }
4678	        // check level 2: verify undo validity
4679	        if (nCheckLevel >= 2 && pindex) {
4680	            CBlockUndo undo;
4681	            if (!pindex->GetUndoPos().IsNull()) {
4682	                if (!chainstate.m_blockman.ReadBlockUndo(undo, *pindex)) {
4683	                    LogError("Verification error: found bad undo data at %d, hash=%s", pindex->nHeight, pindex->GetBlockHash().ToString());
4684	                    return VerifyDBResult::CORRUPTED_BLOCK_DB;
4685	                }
4686	            }
4687	        }
4688	        // check level 3: check for inconsistencies during memory-only disconnect of tip blocks
4689	        size_t curr_coins_usage = coins.DynamicMemoryUsage() + chainstate.CoinsTip().DynamicMemoryUsage();
4690	
4691	        if (nCheckLevel >= 3) {
4692	            if (curr_coins_usage <= chainstate.m_coinstip_cache_size_bytes) {
4693	                assert(coins.GetBestBlock() == pindex->GetBlockHash());
4694	                DisconnectResult res = chainstate.DisconnectBlock(block, pindex, coins);
4695	                if (res == DISCONNECT_FAILED) {
4696	                    LogError("Verification error: irrecoverable inconsistency in block data at %d, hash=%s", pindex->nHeight, pindex->GetBlockHash().ToString());
4697	                    return VerifyDBResult::CORRUPTED_BLOCK_DB;
4698	                }
4699	                if (res == DISCONNECT_UNCLEAN) {
4700	                    nGoodTransactions = 0;
4701	                    pindexFailure = pindex;
4702	                } else {
4703	                    nGoodTransactions += block.vtx.size();
4704	                }
4705	            } else {
4706	                skipped_l3_checks = true;
4707	            }
4708	        }
4709	        if (chainstate.m_chainman.m_interrupt) return VerifyDBResult::INTERRUPTED;
4710	    }
4711	    if (pindexFailure) {
4712	        LogError("Verification error: coin database inconsistencies found (last %i blocks, %i good transactions before that)", chainstate.m_chain.Height() - pindexFailure->nHeight + 1, nGoodTransactions);
4713	        return VerifyDBResult::CORRUPTED_BLOCK_DB;
4714	    }
4715	    if (skipped_l3_checks) {
4716	        LogWarning("Skipped verification of level >=3 (insufficient database cache size). Consider increasing -dbcache.");
4717	    }
4718	
4719	    // store block count as we move pindex at check level >= 4
4720	    int block_count = chainstate.m_chain.Height() - pindex->nHeight;
4721	
4722	    // check level 4: try reconnecting blocks
4723	    if (nCheckLevel >= 4 && !skipped_l3_checks) {
4724	        while (pindex != chainstate.m_chain.Tip()) {
4725	            const int percentageDone = std::max(1, std::min(99, 100 - (int)(((double)(chainstate.m_chain.Height() - pindex->nHeight)) / (double)nCheckDepth * 50)));
4726	            if (reportDone < percentageDone / 10) {
4727	                // report every 10% step
4728	                LogInfo("Verification progress: %d%%", percentageDone);
4729	                reportDone = percentageDone / 10;
4730	            }
4731	            m_notifications.progress(_("Verifying blocks…"), percentageDone, false);
4732	            pindex = chainstate.m_chain.Next(*pindex);
4733	            CBlock block;
4734	            if (!chainstate.m_blockman.ReadBlock(block, *pindex)) {
4735	                LogError("Verification error: ReadBlock failed at %d, hash=%s", pindex->nHeight, pindex->GetBlockHash().ToString());
4736	                return VerifyDBResult::CORRUPTED_BLOCK_DB;
4737	            }
4738	            if (!chainstate.ConnectBlock(block, state, pindex, coins)) {
4739	                LogError("Verification error: found unconnectable block at %d, hash=%s (%s)", pindex->nHeight, pindex->GetBlockHash().ToString(), state.ToString());
4740	                return VerifyDBResult::CORRUPTED_BLOCK_DB;
4741	            }
4742	            if (chainstate.m_chainman.m_interrupt) return VerifyDBResult::INTERRUPTED;
4743	        }
4744	    }
4745	
4746	    LogInfo("Verification: checked last %i blocks at level %i", block_count, nCheckLevel);
4747	    if (nCheckLevel >= 3 && !skipped_l3_checks) {
4748	        LogInfo("Verification: no coin database inconsistencies (%i transactions)", nGoodTransactions);
4749	    }
4750	
4751	    if (skipped_l3_checks) {
4752	        return VerifyDBResult::SKIPPED_L3_CHECKS;
4753	    }
4754	    if (skipped_no_block_data) {
4755	        return VerifyDBResult::SKIPPED_MISSING_BLOCKS;
4756	    }
4757	    return VerifyDBResult::SUCCESS;
4758	}
