4760	/** Apply the effects of a block on the utxo cache, ignoring that it may already have been applied. */
4761	bool Chainstate::RollforwardBlock(const CBlockIndex* pindex, CCoinsViewCache& inputs)
4762	{
4763	    AssertLockHeld(cs_main);
4764	    // TODO: merge with ConnectBlock
4765	    CBlock block;
4766	    if (!m_blockman.ReadBlock(block, *pindex)) {
4767	        LogError("ReplayBlock(): ReadBlock failed at %d, hash=%s\n", pindex->nHeight, pindex->GetBlockHash().ToString());
4768	        return false;
4769	    }
4770	
4771	    for (const CTransactionRef& tx : block.vtx) {
4772	        if (!tx->IsCoinBase()) {
4773	            for (const CTxIn &txin : tx->vin) {
4774	                inputs.SpendCoin(txin.prevout);
4775	            }
4776	        }
4777	        // Pass check = true as every addition may be an overwrite.
4778	        AddCoins(inputs, *tx, pindex->nHeight, true);
4779	    }
4780	    return true;
4781	}
4782	
4783	bool Chainstate::ReplayBlocks()
4784	{
4785	    LOCK(cs_main);
4786	
4787	    CCoinsView& db = this->CoinsDB();
4788	    CCoinsViewCache cache(&db);
4789	
4790	    std::vector<uint256> hashHeads = db.GetHeadBlocks();
4791	    if (hashHeads.empty()) return true; // We're already in a consistent state.
4792	    if (hashHeads.size() != 2) {
4793	        LogError("ReplayBlocks(): unknown inconsistent state\n");
4794	        return false;
4795	    }
4796	
4797	    m_chainman.GetNotifications().progress(_("Replaying blocks…"), 0, false);
4798	    LogInfo("Replaying blocks");
4799	
4800	    const CBlockIndex* pindexOld = nullptr;  // Old tip during the interrupted flush.
4801	    const CBlockIndex* pindexNew;            // New tip during the interrupted flush.
4802	    const CBlockIndex* pindexFork = nullptr; // Latest block common to both the old and the new tip.
4803	
4804	    if (!m_blockman.m_block_index.contains(hashHeads[0])) {
4805	        LogError("ReplayBlocks(): reorganization to unknown block requested\n");
4806	        return false;
4807	    }
4808	    pindexNew = &(m_blockman.m_block_index[hashHeads[0]]);
4809	
4810	    if (!hashHeads[1].IsNull()) { // The old tip is allowed to be 0, indicating it's the first flush.
4811	        if (!m_blockman.m_block_index.contains(hashHeads[1])) {
4812	            LogError("ReplayBlocks(): reorganization from unknown block requested\n");
4813	            return false;
4814	        }
4815	        pindexOld = &(m_blockman.m_block_index[hashHeads[1]]);
4816	        pindexFork = LastCommonAncestor(pindexOld, pindexNew);
4817	        assert(pindexFork != nullptr);
4818	    }
4819	
4820	    // Rollback along the old branch.
4821	    const int nForkHeight{pindexFork ? pindexFork->nHeight : 0};
4822	    if (pindexOld != pindexFork) {
4823	        LogInfo("Rolling back from %s (%i to %i)", pindexOld->GetBlockHash().ToString(), pindexOld->nHeight, nForkHeight);
4824	        while (pindexOld != pindexFork) {
4825	            if (pindexOld->nHeight > 0) { // Never disconnect the genesis block.
4826	                CBlock block;
4827	                if (!m_blockman.ReadBlock(block, *pindexOld)) {
4828	                    LogError("RollbackBlock(): ReadBlock() failed at %d, hash=%s\n", pindexOld->nHeight, pindexOld->GetBlockHash().ToString());
4829	                    return false;
4830	                }
4831	                if (pindexOld->nHeight % 10'000 == 0) {
4832	                    LogInfo("Rolling back %s (%i)", pindexOld->GetBlockHash().ToString(), pindexOld->nHeight);
4833	                }
4834	                DisconnectResult res = DisconnectBlock(block, pindexOld, cache);
4835	                if (res == DISCONNECT_FAILED) {
4836	                    LogError("RollbackBlock(): DisconnectBlock failed at %d, hash=%s\n", pindexOld->nHeight, pindexOld->GetBlockHash().ToString());
4837	                    return false;
4838	                }
4839	                // If DISCONNECT_UNCLEAN is returned, it means a non-existing UTXO was deleted, or an existing UTXO was
4840	                // overwritten. It corresponds to cases where the block-to-be-disconnect never had all its operations
4841	                // applied to the UTXO set. However, as both writing a UTXO and deleting a UTXO are idempotent operations,
4842	                // the result is still a version of the UTXO set with the effects of that block undone.
4843	            }
4844	            pindexOld = pindexOld->pprev;
4845	        }
4846	        LogInfo("Rolled back to %s", pindexFork->GetBlockHash().ToString());
4847	    }
4848	
4849	    // Roll forward from the forking point to the new tip.
4850	    if (nForkHeight < pindexNew->nHeight) {
4851	        LogInfo("Rolling forward to %s (%i to %i)", pindexNew->GetBlockHash().ToString(), nForkHeight, pindexNew->nHeight);
4852	        for (int nHeight = nForkHeight + 1; nHeight <= pindexNew->nHeight; ++nHeight) {
4853	            const CBlockIndex& pindex{*Assert(pindexNew->GetAncestor(nHeight))};
4854	
4855	            if (nHeight % 10'000 == 0) {
4856	                LogInfo("Rolling forward %s (%i)", pindex.GetBlockHash().ToString(), nHeight);
4857	            }
4858	            m_chainman.GetNotifications().progress(_("Replaying blocks…"), (int)((nHeight - nForkHeight) * 100.0 / (pindexNew->nHeight - nForkHeight)), false);
4859	            if (!RollforwardBlock(&pindex, cache)) return false;
4860	        }
4861	        LogInfo("Rolled forward to %s", pindexNew->GetBlockHash().ToString());
4862	    }
4863	
4864	    cache.SetBestBlock(pindexNew->GetBlockHash());
4865	    cache.Flush(/*reallocate_cache=*/false); // local CCoinsViewCache goes out of scope
4866	    m_chainman.GetNotifications().progress(bilingual_str{}, 100, false);
4867	    return true;
4868	}
