5469	bool Chainstate::ResizeCoinsCaches(size_t coinstip_size, size_t coinsdb_size)
5470	{
5471	    AssertLockHeld(::cs_main);
5472	    if (coinstip_size == m_coinstip_cache_size_bytes &&
5473	            coinsdb_size == m_coinsdb_cache_size_bytes) {
5474	        // Cache sizes are unchanged, no need to continue.
5475	        return true;
5476	    }
5477	    size_t old_coinstip_size = m_coinstip_cache_size_bytes;
5478	    m_coinstip_cache_size_bytes = coinstip_size;
5479	    m_coinsdb_cache_size_bytes = coinsdb_size;
5480	    CoinsDB().ResizeCache(coinsdb_size);
5481	
5482	    LogInfo("[%s] resized coinsdb cache to %.1f MiB",
5483	        this->ToString(), coinsdb_size / double(1_MiB));
5484	    LogInfo("[%s] resized coinstip cache to %.1f MiB",
5485	        this->ToString(), coinstip_size / double(1_MiB));
5486	
5487	    BlockValidationState state;
5488	    bool ret;
5489	
5490	    if (coinstip_size > old_coinstip_size) {
5491	        // Likely no need to flush if cache sizes have grown.
5492	        ret = FlushStateToDisk(state, FlushStateMode::IF_NEEDED);
5493	    } else {
5494	        // Otherwise, flush state to disk and deallocate the in-memory coins map.
5495	        ret = FlushStateToDisk(state, FlushStateMode::FORCE_FLUSH);
5496	    }
5497	    return ret;
5498	}
