5500	double ChainstateManager::GuessVerificationProgress(const CBlockIndex* pindex) const
5501	{
5502	    AssertLockHeld(GetMutex());
5503	    const ChainTxData& data{GetParams().TxData()};
5504	    if (pindex == nullptr) {
5505	        return 0.0;
5506	    }
5507	
5508	    if (pindex->m_chain_tx_count == 0) {
5509	        LogDebug(BCLog::VALIDATION, "Block %d has unset m_chain_tx_count. Unable to estimate verification progress.\n", pindex->nHeight);
5510	        return 0.0;
5511	    }
5512	
5513	    const int64_t nNow{TicksSinceEpoch<std::chrono::seconds>(NodeClock::now())};
5514	    const auto block_time{
5515	        (Assume(m_best_header) && std::abs(nNow - pindex->GetBlockTime()) <= Ticks<std::chrono::seconds>(2h) &&
5516	         Assume(m_best_header->nHeight >= pindex->nHeight)) ?
5517	            // When the header is known to be recent, switch to a height-based
5518	            // approach. This ensures the returned value is quantized when
5519	            // close to "1.0", because some users expect it to be. This also
5520	            // avoids relying too much on the exact miner-set timestamp, which
5521	            // may be off.
5522	            nNow - (m_best_header->nHeight - pindex->nHeight) * GetConsensus().nPowTargetSpacing :
5523	            pindex->GetBlockTime(),
5524	    };
5525	
5526	    double fTxTotal;
5527	
5528	    if (pindex->m_chain_tx_count <= data.tx_count) {
5529	        fTxTotal = data.tx_count + (nNow - data.nTime) * data.dTxRate;
5530	    } else {
5531	        fTxTotal = pindex->m_chain_tx_count + (nNow - block_time) * data.dTxRate;
5532	    }
5533	
5534	    return std::min<double>(pindex->m_chain_tx_count / fTxTotal, 1.0);
5535	}
