5537	double ChainstateManager::GetBackgroundVerificationProgress(const CBlockIndex& pindex) const
5538	{
5539	    AssertLockHeld(GetMutex());
5540	    Assert(HistoricalChainstate());
5541	    auto target_block = HistoricalChainstate()->TargetBlock();
5542	
5543	    if (pindex.m_chain_tx_count == 0 || target_block->m_chain_tx_count == 0) {
5544	        LogDebug(BCLog::VALIDATION, "[background validation] Block %d has unset m_chain_tx_count. Unable to estimate verification progress.", pindex.nHeight);
5545	        return 0.0;
5546	    }
5547	    return static_cast<double>(pindex.m_chain_tx_count) / static_cast<double>(target_block->m_chain_tx_count);
5548	}
