5558	[[nodiscard]] static bool DeleteCoinsDBFromDisk(const fs::path db_path, bool is_snapshot)
5559	    EXCLUSIVE_LOCKS_REQUIRED(::cs_main)
5560	{
5561	    AssertLockHeld(::cs_main);
5562	
5563	    if (is_snapshot) {
5564	        fs::path base_blockhash_path = db_path / node::SNAPSHOT_BLOCKHASH_FILENAME;
5565	
5566	        try {
5567	            bool existed = fs::remove(base_blockhash_path);
5568	            if (!existed) {
5569	                LogWarning("[snapshot] snapshot chainstate dir being removed lacks %s file",
5570	                          fs::PathToString(node::SNAPSHOT_BLOCKHASH_FILENAME));
5571	            }
5572	        } catch (const fs::filesystem_error& e) {
5573	            LogWarning("[snapshot] failed to remove file %s: %s\n",
5574	                       fs::PathToString(base_blockhash_path), e.code().message());
5575	        }
5576	    }
5577	
5578	    std::string path_str = fs::PathToString(db_path);
5579	    LogInfo("Removing leveldb dir at %s\n", path_str);
5580	
5581	    // We have to destruct before this call leveldb::DB in order to release the db
5582	    // lock, otherwise `DestroyDB` will fail. See `leveldb::~DBImpl()`.
5583	    const bool destroyed = DestroyDB(path_str);
5584	
5585	    if (!destroyed) {
5586	        LogError("leveldb DestroyDB call failed on %s", path_str);
5587	    }
5588	
5589	    // Datadir should be removed from filesystem; otherwise initialization may detect
5590	    // it on subsequent statups and get confused.
5591	    //
5592	    // If the base_blockhash_path removal above fails in the case of snapshot
5593	    // chainstates, this will return false since leveldb won't remove a non-empty
5594	    // directory.
5595	    return destroyed && !fs::exists(db_path);
5596	}
