5741	{
5742	    LOG_TIME_MILLIS_WITH_CATEGORY_MSG_ONCE(
5743	        strprintf("%s (%.2f MB)",
5744	                  snapshot_loaded ? "saving snapshot chainstate" : "flushing coins cache",
5745	                  coins_cache.DynamicMemoryUsage() / (1000 * 1000)),
5746	        BCLog::LogFlags::ALL);
