3330	bool Chainstate::ActivateBestChain(BlockValidationState& state, std::shared_ptr<const CBlock> pblock)
3331	{
3332	    AssertLockNotHeld(m_chainstate_mutex);
3333	
3334	    // Note that while we're often called here from ProcessNewBlock, this is
3335	    // far from a guarantee. Things in the P2P/RPC will often end up calling
3336	    // us in the middle of ProcessNewBlock - do not assume pblock is set
3337	    // sanely for performance or correctness!
3338	    AssertLockNotHeld(::cs_main);
3339	
3340	    // ABC maintains a fair degree of expensive-to-calculate internal state
3341	    // because this function periodically releases cs_main so that it does not lock up other threads for too long
3342	    // during large connects - and to allow for e.g. the callback queue to drain
3343	    // we use m_chainstate_mutex to enforce mutual exclusion so that only one caller may execute this function at a time
3344	    LOCK(m_chainstate_mutex);
3345	
3346	    // Belt-and-suspenders check that we aren't attempting to advance the
3347	    // chainstate past the target block.
3348	    if (WITH_LOCK(::cs_main, return m_target_utxohash)) {
3349	        LogError("%s", STR_INTERNAL_BUG("m_target_utxohash is set - this chainstate should not be in operation."));
3350	        return Assume(false);
3351	    }
3352	
3353	    CBlockIndex *pindexMostWork = nullptr;
3354	    CBlockIndex *pindexNewTip = nullptr;
3355	    bool exited_ibd{false};
3356	    do {
3357	        // Block until the validation queue drains. This should largely
3358	        // never happen in normal operation, however may happen during
3359	        // reindex, causing memory blowup if we run too far ahead.
3360	        // Note that if a validationinterface callback ends up calling
3361	        // ActivateBestChain this may lead to a deadlock! We should
3362	        // probably have a DEBUG_LOCKORDER test for this in the future.
3363	        if (m_chainman.m_options.signals) LimitValidationInterfaceQueue(*m_chainman.m_options.signals);
3364	
3365	        {
3366	            LOCK(cs_main);
3367	            {
3368	            // Lock transaction pool for at least as long as it takes for connected_blocks to be consumed
3369	            LOCK(MempoolMutex());
3370	            const bool was_in_ibd = m_chainman.IsInitialBlockDownload();
3371	            CBlockIndex* starting_tip = m_chain.Tip();
3372	            bool blocks_connected = false;
3373	            do {
3374	                // We absolutely may not unlock cs_main until we've made forward progress
3375	                // (with the exception of shutdown due to hardware issues, low disk space, etc).
3376	                std::vector<ConnectedBlock> connected_blocks; // Destructed before cs_main is unlocked
3377	
3378	                if (pindexMostWork == nullptr) {
3379	                    pindexMostWork = FindMostWorkChain();
3380	                }
3381	
3382	                // Whether we have anything to do at all.
3383	                if (pindexMostWork == nullptr || pindexMostWork == m_chain.Tip()) {
3384	                    break;
3385	                }
3386	
3387	                bool fInvalidFound = false;
3388	                std::shared_ptr<const CBlock> nullBlockPtr;
3389	                // BlockConnected signals must be sent for the original role;
3390	                // in case snapshot validation is completed during ActivateBestChainStep, the
3391	                // result of GetRole() changes from BACKGROUND to NORMAL.
3392	               const ChainstateRole chainstate_role{this->GetRole()};
3393	                if (!ActivateBestChainStep(state, *pindexMostWork, pblock && pblock->GetHash() == pindexMostWork->GetBlockHash() ? pblock : nullBlockPtr, fInvalidFound, connected_blocks)) {
3394	                    // A system error occurred
3395	                    return false;
3396	                }
3397	                blocks_connected = true;
3398	
3399	                if (fInvalidFound) {
3400	                    // Wipe cache, we may need another branch now.
3401	                    pindexMostWork = nullptr;
3402	                }
3403	                pindexNewTip = m_chain.Tip();
3404	
3405	                for (auto& [index, block] : std::move(connected_blocks)) {
3406	                    if (m_chainman.m_options.signals) {
3407	                        m_chainman.m_options.signals->BlockConnected(chainstate_role, std::move(Assert(block)), Assert(index));
3408	                    }
3409	                }
3410	
3411	                // Break this do-while to ensure we don't advance past the target block.
3412	                if (ReachedTarget()) {
3413	                    break;
3414	                }
3415	            } while (!m_chain.Tip() || (starting_tip && CBlockIndexWorkComparator()(m_chain.Tip(), starting_tip)));
3416	            if (!blocks_connected) return true;
3417	
3418	            const CBlockIndex* pindexFork = starting_tip ? m_chain.FindFork(*starting_tip) : nullptr;
3419	            bool still_in_ibd = m_chainman.IsInitialBlockDownload();
3420	
3421	            if (was_in_ibd && !still_in_ibd) {
3422	                // Active chainstate has exited IBD.
3423	                exited_ibd = true;
3424	            }
3425	
3426	            // Notify external listeners about the new tip.
3427	            // Enqueue while holding cs_main to ensure that UpdatedBlockTip is called in the order in which blocks are connected
3428	            if (this == &m_chainman.ActiveChainstate() && pindexFork != pindexNewTip) {
3429	                // Notify ValidationInterface subscribers
3430	                if (m_chainman.m_options.signals) {
3431	                    m_chainman.m_options.signals->UpdatedBlockTip(pindexNewTip, pindexFork, still_in_ibd);
3432	                }
3433	
3434	                if (kernel::IsInterrupted(m_chainman.GetNotifications().blockTip(
3435	                        /*state=*/GetSynchronizationState(still_in_ibd, m_chainman.m_blockman.m_blockfiles_indexed),
3436	                        /*index=*/*pindexNewTip,
3437	                        /*verification_progress=*/m_chainman.GuessVerificationProgress(pindexNewTip))))
3438	                {
3439	                    // Just breaking and returning success for now. This could
3440	                    // be changed to bubble up the kernel::Interrupted value to
3441	                    // the caller so the caller could distinguish between
3442	                    // completed and interrupted operations.
3443	                    break;
3444	                }
3445	            }
3446	            } // release MempoolMutex
3447	            // Notify external listeners about the new tip, even if pindexFork == pindexNewTip.
3448	            if (m_chainman.m_options.signals && this == &m_chainman.ActiveChainstate()) {
3449	                m_chainman.m_options.signals->ActiveTipChange(*Assert(pindexNewTip), m_chainman.IsInitialBlockDownload());
3450	            }
3451	        } // release cs_main
3452	        // When we reach this point, we switched to a new tip (stored in pindexNewTip).
3453	
3454	        bool reached_target;
3455	        {
3456	            LOCK(m_chainman.GetMutex());
3457	            if (exited_ibd) {
3458	                // If a background chainstate is in use, we may need to rebalance our
3459	                // allocation of caches once a chainstate exits initial block download.
3460	                m_chainman.MaybeRebalanceCaches();
3461	            }
3462	
3463	            // Write changes periodically to disk, after relay.
3464	            if (!FlushStateToDisk(state, FlushStateMode::PERIODIC)) {
3465	                return false;
3466	            }
3467	
3468	            reached_target = ReachedTarget();
3469	        }
3470	
3471	        if (reached_target) {
3472	            // Chainstate has reached the target block, so exit.
3473	            //
3474	            // Restart indexes so indexes can resync and index new blocks after
3475	            // the target block.
3476	            //
3477	            // This cannot be done while holding cs_main (within
3478	            // MaybeValidateSnapshot) or a cs_main deadlock will occur.
3479	            if (m_chainman.snapshot_download_completed) {
3480	                m_chainman.snapshot_download_completed();
3481	            }
3482	            break;
3483	        }
3484	
3485	        // We check interrupt only after giving ActivateBestChainStep a chance to run once so that we
3486	        // never interrupt before connecting the genesis block during LoadChainTip(). Previously this
3487	        // caused an assert() failure during interrupt in such cases as the UTXO DB flushing checks
3488	        // that the best block hash is non-null.
3489	        if (m_chainman.m_interrupt) break;
3490	    } while (pindexNewTip != pindexMostWork);
3491	
3492	    m_chainman.CheckBlockIndex();
3493	
3494	    return true;
3495	}
