3925	bool CheckBlock(const CBlock& block, BlockValidationState& state, const Consensus::Params& consensusParams, bool fCheckPOW, bool fCheckMerkleRoot)
3926	{
3927	    // These are checks that are independent of context.
3928	
3929	    if (block.fChecked)
3930	        return true;
3931	
3932	    // Check that the header is valid (particularly PoW).  This is mostly
3933	    // redundant with the call in AcceptBlockHeader.
3934	    if (!CheckBlockHeader(block, state, consensusParams, fCheckPOW))
3935	        return false;
3936	
3937	    // Signet only: check block solution
3938	    if (consensusParams.signet_blocks && fCheckPOW && !CheckSignetBlockSolution(block, consensusParams)) {
3939	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-signet-blksig", "signet block signature validation failure");
3940	    }
3941	
3942	    // Check the merkle root.
3943	    if (fCheckMerkleRoot && !CheckMerkleRoot(block, state)) {
3944	        return false;
3945	    }
3946	
3947	    // All potential-corruption validation must be done before we do any
3948	    // transaction validation, as otherwise we may mark the header as invalid
3949	    // because we receive the wrong transactions for it.
3950	    // Note that witness malleability is checked in ContextualCheckBlock, so no
3951	    // checks that use witness data may be performed here.
3952	
3953	    // Size limits
3954	    if (block.vtx.empty() || block.vtx.size() * WITNESS_SCALE_FACTOR > MAX_BLOCK_WEIGHT || ::GetSerializeSize(TX_NO_WITNESS(block)) * WITNESS_SCALE_FACTOR > MAX_BLOCK_WEIGHT)
3955	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-blk-length", "size limits failed");
3956	
3957	    // First transaction must be coinbase, the rest must not be
3958	    if (block.vtx.empty() || !block.vtx[0]->IsCoinBase())
3959	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-cb-missing", "first tx is not coinbase");
3960	    for (unsigned int i = 1; i < block.vtx.size(); i++)
3961	        if (block.vtx[i]->IsCoinBase())
3962	            return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-cb-multiple", "more than one coinbase");
3963	
3964	    // Check transactions
3965	    // Must check for duplicate inputs (see CVE-2018-17144)
3966	    for (const auto& tx : block.vtx) {
3967	        TxValidationState tx_state;
3968	        if (!CheckTransaction(*tx, tx_state)) {
3969	            // CheckBlock() does context-free validation checks. The only
3970	            // possible failures are consensus failures.
3971	            assert(tx_state.GetResult() == TxValidationResult::TX_CONSENSUS);
3972	            return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, tx_state.GetRejectReason(),
3973	                                 strprintf("Transaction check failed (tx hash %s) %s", tx->GetHash().ToString(), tx_state.GetDebugMessage()));
3974	        }
3975	    }
3976	    // This underestimates the number of sigops, because unlike ConnectBlock it
3977	    // does not count witness and p2sh sigops.
3978	    unsigned int nSigOps = 0;
3979	    for (const auto& tx : block.vtx)
3980	    {
3981	        nSigOps += GetLegacySigOpCount(*tx);
3982	    }
3983	    if (nSigOps * WITNESS_SCALE_FACTOR > MAX_BLOCK_SIGOPS_COST)
3984	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-blk-sigops", "out-of-bounds SigOpCount");
3985	
3986	    if (fCheckPOW && fCheckMerkleRoot)
3987	        block.fChecked = true;
3988	
3989	    return true;
3990	}
