4012	        out.nValue = 0;
4013	        out.scriptPubKey.resize(MINIMUM_WITNESS_COMMITMENT);
4014	        out.scriptPubKey[0] = OP_RETURN;
4015	        out.scriptPubKey[1] = 0x24;
4016	        out.scriptPubKey[2] = 0xaa;
4017	        out.scriptPubKey[3] = 0x21;
4018	        out.scriptPubKey[4] = 0xa9;
4019	        out.scriptPubKey[5] = 0xed;
4020	        memcpy(&out.scriptPubKey[6], witnessroot.begin(), 32);
4021	        CMutableTransaction tx(*block.vtx[0]);
4022	        tx.vout.push_back(out);
4023	        block.vtx[0] = MakeTransactionRef(std::move(tx));
4024	    }
4025	    UpdateUncommittedBlockStructures(block, pindexPrev);
4026	}
