4590	              FormatISO8601DateTime(tip->GetBlockTime()),
4591	              m_chainman.GuessVerificationProgress(tip));
4592	
4593	    // Ensure KernelNotifications m_tip_block is set even if no new block arrives.
4594	    if (!this->GetRole().historical) {
4595	        // Ignoring return value for now.
4596	        (void)m_chainman.GetNotifications().blockTip(
4597	            /*state=*/GetSynchronizationState(/*init=*/true, m_chainman.m_blockman.m_blockfiles_indexed),
4598	            /*index=*/*pindex,
