3180	/** Delete all entries in setBlockIndexCandidates that are worse than the current tip. */
3181	void Chainstate::PruneBlockIndexCandidates() {
3182	    // Note that we can't delete the current block itself, as we may need to return to it later in case a
3183	    // reorganization to a better block fails.
3184	    std::set<CBlockIndex*, CBlockIndexWorkComparator>::iterator it = setBlockIndexCandidates.begin();
3185	    while (it != setBlockIndexCandidates.end() && setBlockIndexCandidates.value_comp()(*it, m_chain.Tip())) {
3186	        setBlockIndexCandidates.erase(it++);
3187	    }
3188	    // Either the current tip or a successor of it we're working towards is left in setBlockIndexCandidates.
3189	    assert(!setBlockIndexCandidates.empty());
3190	}
