3192	/**
3193	 * Try to make some progress towards making index_most_work the active block.
3194	 * pblock is either nullptr or a pointer to a CBlock corresponding to index_most_work.
3195	 *
3196	 * @returns true unless a system error occurred
3197	 */
3198	bool Chainstate::ActivateBestChainStep(BlockValidationState& state, CBlockIndex& index_most_work, const std::shared_ptr<const CBlock>& pblock, bool& fInvalidFound, std::vector<ConnectedBlock>& connected_blocks)
3199	{
3200	    AssertLockHeld(cs_main);
3201	    if (m_mempool) AssertLockHeld(m_mempool->cs);
3202	
3203	    const CBlockIndex* pindexOldTip = m_chain.Tip();
3204	    const CBlockIndex* pindexFork = m_chain.FindFork(index_most_work);
3205	
3206	    // Disconnect active blocks which are no longer in the best chain.
3207	    bool fBlocksDisconnected = false;
3208	    DisconnectedBlockTransactions disconnectpool{MAX_DISCONNECTED_TX_POOL_BYTES};
3209	    while (m_chain.Tip() && m_chain.Tip() != pindexFork) {
3210	        if (!DisconnectTip(state, &disconnectpool)) {
3211	            // This is likely a fatal error, but keep the mempool consistent,
3212	            // just in case. Only remove from the mempool in this case.
3213	            MaybeUpdateMempoolForReorg(disconnectpool, false);
3214	
3215	            // If we're unable to disconnect a block during normal operation,
3216	            // then that is a failure of our local system -- we should abort
3217	            // rather than stay on a less work chain.
3218	            FatalError(m_chainman.GetNotifications(), state, _("Failed to disconnect block."));
3219	            return false;
3220	        }
3221	        fBlocksDisconnected = true;
3222	    }
3223	
3224	    // Build list of new blocks to connect (in descending height order).
3225	    std::vector<CBlockIndex*> vpindexToConnect;
3226	    bool fContinue = true;
3227	    int nHeight = pindexFork ? pindexFork->nHeight : -1;
3228	    while (fContinue && nHeight != index_most_work.nHeight) {
3229	        // Don't iterate the entire list of potential improvements toward the best tip, as we likely only need
3230	        // a few blocks along the way.
3231	        int nTargetHeight = std::min(nHeight + 32, index_most_work.nHeight);
3232	        vpindexToConnect.clear();
3233	        vpindexToConnect.reserve(nTargetHeight - nHeight);
3234	        CBlockIndex* pindexIter = index_most_work.GetAncestor(nTargetHeight);
3235	        while (pindexIter && pindexIter->nHeight != nHeight) {
3236	            vpindexToConnect.push_back(pindexIter);
3237	            pindexIter = pindexIter->pprev;
3238	        }
3239	        nHeight = nTargetHeight;
3240	
3241	        // Connect new blocks.
3242	        for (CBlockIndex* pindexConnect : vpindexToConnect | std::views::reverse) {
3243	            if (!ConnectTip(state, pindexConnect, pindexConnect == &index_most_work ? pblock : std::shared_ptr<const CBlock>(), connected_blocks, disconnectpool)) {
3244	                if (state.IsInvalid()) {
3245	                    // The block violates a consensus rule.
3246	                    if (state.GetResult() != BlockValidationResult::BLOCK_MUTATED) {
3247	                        InvalidChainFound(vpindexToConnect.front());
3248	                    }
3249	                    state = BlockValidationState();
3250	                    fInvalidFound = true;
3251	                    fContinue = false;
3252	                    break;
3253	                } else {
3254	                    // A system error occurred (disk space, database error, ...).
3255	                    // Make the mempool consistent with the current tip, just in case
3256	                    // any observers try to use it before shutdown.
3257	                    MaybeUpdateMempoolForReorg(disconnectpool, false);
3258	                    return false;
3259	                }
3260	            } else {
3261	                PruneBlockIndexCandidates();
3262	                if (!pindexOldTip || m_chain.Tip()->nChainWork > pindexOldTip->nChainWork) {
3263	                    // We're in a better position than we were. Return temporarily to release the lock.
3264	                    fContinue = false;
3265	                    break;
3266	                }
3267	            }
3268	        }
3269	    }
3270	
3271	    if (fBlocksDisconnected) {
3272	        // If any blocks were disconnected, disconnectpool may be non empty.  Add
3273	        // any disconnected transactions back to the mempool.
3274	        MaybeUpdateMempoolForReorg(disconnectpool, true);
3275	    }
3276	    if (m_mempool) m_mempool->check(this->CoinsTip(), this->m_chain.Height() + 1);
3277	
3278	    CheckForkWarningConditions();
3279	
3280	    return true;
3281	}
