4966	void ChainstateManager::LoadExternalBlockFile(
4967	    AutoFile& file_in,
4968	    FlatFilePos* dbp,
4969	    std::multimap<uint256, FlatFilePos>* blocks_with_unknown_parent)
4970	{
4971	    // Either both should be specified (-reindex), or neither (-loadblock).
4972	    assert(!dbp == !blocks_with_unknown_parent);
4973	
4974	    const auto start{SteadyClock::now()};
4975	    const CChainParams& params{GetParams()};
4976	
4977	    int nLoaded = 0;
4978	    try {
4979	        BufferedFile blkdat{file_in, 2 * MAX_BLOCK_SERIALIZED_SIZE, MAX_BLOCK_SERIALIZED_SIZE + 8};
4980	        // nRewind indicates where to resume scanning in case something goes wrong,
4981	        // such as a block fails to deserialize.
4982	        uint64_t nRewind = blkdat.GetPos();
4983	        while (!blkdat.eof()) {
4984	            if (m_interrupt) return;
4985	
4986	            blkdat.SetPos(nRewind);
4987	            nRewind++; // start one byte further next time, in case of failure
4988	            blkdat.SetLimit(); // remove former limit
4989	            unsigned int nSize = 0;
4990	            try {
4991	                // locate a header
4992	                MessageStartChars buf;
4993	                blkdat.FindByte(std::byte(params.MessageStart()[0]));
4994	                nRewind = blkdat.GetPos() + 1;
4995	                blkdat >> buf;
4996	                if (buf != params.MessageStart()) {
4997	                    continue;
4998	                }
4999	                // read size
5000	                blkdat >> nSize;
5001	                if (nSize < 80 || nSize > MAX_BLOCK_SERIALIZED_SIZE)
5002	                    continue;
5003	            } catch (const std::exception&) {
5004	                // no valid block header found; don't complain
5005	                // (this happens at the end of every blk.dat file)
5006	                break;
5007	            }
5008	            try {
5009	                // read block header
5010	                const uint64_t nBlockPos{blkdat.GetPos()};
5011	                if (dbp)
5012	                    dbp->nPos = nBlockPos;
5013	                blkdat.SetLimit(nBlockPos + nSize);
5014	                CBlockHeader header;
5015	                blkdat >> header;
5016	                const uint256 hash{header.GetHash()};
5017	                // Skip the rest of this block (this may read from disk into memory); position to the marker before the
5018	                // next block, but it's still possible to rewind to the start of the current block (without a disk read).
5019	                nRewind = nBlockPos + nSize;
5020	                blkdat.SkipTo(nRewind);
5021	
5022	                std::shared_ptr<CBlock> pblock{}; // needs to remain available after the cs_main lock is released to avoid duplicate reads from disk
5023	
5024	                {
5025	                    LOCK(cs_main);
5026	                    // detect out of order blocks, and store them for later
5027	                    if (hash != params.GetConsensus().hashGenesisBlock && !m_blockman.LookupBlockIndex(header.hashPrevBlock)) {
5028	                        LogDebug(BCLog::REINDEX, "%s: Out of order block %s, parent %s not known\n", __func__, hash.ToString(),
5029	                                 header.hashPrevBlock.ToString());
5030	                        if (dbp && blocks_with_unknown_parent) {
5031	                            blocks_with_unknown_parent->emplace(header.hashPrevBlock, *dbp);
5032	                        }
5033	                        continue;
5034	                    }
5035	
5036	                    // process in case the block isn't known yet
5037	                    const CBlockIndex* pindex = m_blockman.LookupBlockIndex(hash);
5038	                    if (!pindex || (pindex->nStatus & BLOCK_HAVE_DATA) == 0) {
5039	                        // This block can be processed immediately; rewind to its start, read and deserialize it.
5040	                        blkdat.SetPos(nBlockPos);
5041	                        pblock = std::make_shared<CBlock>();
5042	                        blkdat >> TX_WITH_WITNESS(*pblock);
5043	                        nRewind = blkdat.GetPos();
5044	
5045	                        BlockValidationState state;
5046	                        if (AcceptBlock(pblock, state, nullptr, true, dbp, nullptr, true)) {
5047	                            nLoaded++;
5048	                        }
5049	                        if (state.IsError()) {
5050	                            break;
5051	                        }
5052	                    } else if (hash != params.GetConsensus().hashGenesisBlock && pindex->nHeight % 1000 == 0) {
5053	                        LogDebug(BCLog::REINDEX, "Block Import: already had block %s at height %d\n", hash.ToString(), pindex->nHeight);
5054	                    }
5055	                }
5056	
5057	                // Activate the genesis block so normal node progress can continue
5058	                // During first -reindex, this will only connect Genesis since
5059	                // ActivateBestChain only connects blocks which are in the block tree db,
5060	                // which only contains blocks whose parents are in it.
5061	                // But do this only if genesis isn't activated yet, to avoid connecting many blocks
5062	                // without assumevalid in the case of a continuation of a reindex that
5063	                // was interrupted by the user.
5064	                if (hash == params.GetConsensus().hashGenesisBlock && WITH_LOCK(::cs_main, return ActiveHeight()) == -1) {
5065	                    BlockValidationState state;
5066	                    if (!ActiveChainstate().ActivateBestChain(state, nullptr)) {
5067	                        break;
5068	                    }
5069	                }
5070	
5071	                if (m_blockman.IsPruneMode() && m_blockman.m_blockfiles_indexed && pblock) {
5072	                    // must update the tip for pruning to work while importing with -loadblock.
5073	                    // this is a tradeoff to conserve disk space at the expense of time
5074	                    // spent updating the tip to be able to prune.
5075	                    // otherwise, ActivateBestChain won't be called by the import process
5076	                    // until after all of the block files are loaded. ActivateBestChain can be
5077	                    // called by concurrent network message processing. but, that is not
5078	                    // reliable for the purpose of pruning while importing.
5079	                    if (auto result{ActivateBestChains()}; !result) {
5080	                        LogDebug(BCLog::REINDEX, "%s\n", util::ErrorString(result).original);
5081	                        break;
5082	                    }
5083	                }
5084	
5085	                NotifyHeaderTip();
5086	
5087	                if (!blocks_with_unknown_parent) continue;
5088	
5089	                // Recursively process earlier encountered successors of this block
5090	                std::deque<uint256> queue;
5091	                queue.push_back(hash);
5092	                while (!queue.empty()) {
5093	                    uint256 head = queue.front();
5094	                    queue.pop_front();
5095	                    auto range = blocks_with_unknown_parent->equal_range(head);
5096	                    while (range.first != range.second) {
5097	                        std::multimap<uint256, FlatFilePos>::iterator it = range.first;
5098	                        std::shared_ptr<CBlock> pblockrecursive = std::make_shared<CBlock>();
5099	                        if (m_blockman.ReadBlock(*pblockrecursive, it->second, {})) {

5200	    const CBlockIndex *snap_first_missing{}, *snap_first_notx{}, *snap_first_notv{}, *snap_first_nocv{}, *snap_first_nosv{};
5201	    auto snap_update_firsts = [&] {
5202	        if (pindex == snap_base) {
5203	            std::swap(snap_first_missing, pindexFirstMissing);
5204	            std::swap(snap_first_notx, pindexFirstNeverProcessed);
5205	            std::swap(snap_first_notv, pindexFirstNotTransactionsValid);
5206	            std::swap(snap_first_nocv, pindexFirstNotChainValid);
5207	            std::swap(snap_first_nosv, pindexFirstNotScriptsValid);
5208	        }
5209	    };
5210	
5211	    while (pindex != nullptr) {
5212	        nNodes++;
5213	        if (pindexFirstInvalid == nullptr && pindex->nStatus & BLOCK_FAILED_VALID) pindexFirstInvalid = pindex;
5214	        if (pindexFirstMissing == nullptr && !(pindex->nStatus & BLOCK_HAVE_DATA)) {
5215	            pindexFirstMissing = pindex;
5216	        }
5217	        if (pindexFirstNeverProcessed == nullptr && pindex->nTx == 0) pindexFirstNeverProcessed = pindex;
5218	        if (pindex->pprev != nullptr && pindexFirstNotTreeValid == nullptr && (pindex->nStatus & BLOCK_VALID_MASK) < BLOCK_VALID_TREE) pindexFirstNotTreeValid = pindex;
5219	
5220	        if (pindex->pprev != nullptr) {
5221	            if (pindexFirstNotTransactionsValid == nullptr &&
5222	                    (pindex->nStatus & BLOCK_VALID_MASK) < BLOCK_VALID_TRANSACTIONS) {
5223	                pindexFirstNotTransactionsValid = pindex;
5224	            }
5225	
5226	            if (pindexFirstNotChainValid == nullptr &&
5227	                    (pindex->nStatus & BLOCK_VALID_MASK) < BLOCK_VALID_CHAIN) {
5228	                pindexFirstNotChainValid = pindex;
5229	            }
5230	
5231	            if (pindexFirstNotScriptsValid == nullptr &&
5232	                    (pindex->nStatus & BLOCK_VALID_MASK) < BLOCK_VALID_SCRIPTS) {
5233	                pindexFirstNotScriptsValid = pindex;
5234	            }
5235	        }
5236	
5237	        // Begin: actual consistency checks.
5238	        if (pindex->pprev == nullptr) {
5239	            // Genesis block checks.
5240	            assert(pindex->GetBlockHash() == GetConsensus().hashGenesisBlock); // Genesis block's hash must match.
5241	            for (const auto& c : m_chainstates) {
5242	                if (c->m_chain.Genesis() != nullptr) {
