5269	        // HaveNumChainTxs will also be set in the assumeutxo snapshot block from snapshot metadata.
5270	        assert((pindexFirstNeverProcessed == nullptr || pindex == snap_base) == pindex->HaveNumChainTxs());
5271	        assert((pindexFirstNotTransactionsValid == nullptr || pindex == snap_base) == pindex->HaveNumChainTxs());
