5311	            //   or an assumeutxo snapshot never downloaded transactions
5312	            //   (pindexFirstNeverProcessed is non-null), it should not be a
5313	            //   candidate, and this will be asserted below. The only exception
5314	            //   is if pindex itself is an assumeutxo snapshot block. Then it is
5315	            //   also a potential candidate.
5316	            if (!CBlockIndexWorkComparator()(pindex, c->m_chain.Tip()) && (pindexFirstNeverProcessed == nullptr || pindex == snap_base)) {
