317	class CDiskBlockIndex : public CBlockIndex
318	{
319	    /** Historically CBlockLocator's version field has been written to disk
320	     * streams as the client version, but the value has never been used.
321	     *
322	     * Hard-code to the highest client version ever written.
323	     * SerParams can be used if the field requires any meaning in the future.
324	     **/
325	    static constexpr int DUMMY_VERSION = 259900;
326	
327	public:
328	    uint256 hashPrev;
329	
330	    CDiskBlockIndex()
331	    {
332	        hashPrev = uint256();
333	    }
334	
335	    explicit CDiskBlockIndex(const CBlockIndex* pindex) : CBlockIndex(*pindex)
336	    {
337	        hashPrev = (pprev ? pprev->GetBlockHash() : uint256());
338	    }
339	
340	    SERIALIZE_METHODS(CDiskBlockIndex, obj)
341	    {
342	        LOCK(::cs_main);
343	        int _nVersion = DUMMY_VERSION;
344	        READWRITE(VARINT_MODE(_nVersion, VarIntMode::NONNEGATIVE_SIGNED));
345	
346	        READWRITE(VARINT_MODE(obj.nHeight, VarIntMode::NONNEGATIVE_SIGNED));
347	        READWRITE(VARINT(obj.nStatus));
348	        READWRITE(VARINT(obj.nTx));
349	        if (obj.nStatus & (BLOCK_HAVE_DATA | BLOCK_HAVE_UNDO)) READWRITE(VARINT_MODE(obj.nFile, VarIntMode::NONNEGATIVE_SIGNED));
350	        if (obj.nStatus & BLOCK_HAVE_DATA) READWRITE(VARINT(obj.nDataPos));
351	        if (obj.nStatus & BLOCK_HAVE_UNDO) READWRITE(VARINT(obj.nUndoPos));
352	
353	        // block header
354	        READWRITE(obj.nVersion);
355	        READWRITE(obj.hashPrev);
356	        READWRITE(obj.hashMerkleRoot);
357	        READWRITE(obj.nTime);
358	        READWRITE(obj.nBits);
359	        READWRITE(obj.nNonce);
360	    }
361	
362	    uint256 ConstructBlockHash() const
363	    {
364	        CBlockHeader block;
365	        block.nVersion = nVersion;
366	        block.hashPrevBlock = hashPrev;
367	        block.hashMerkleRoot = hashMerkleRoot;
368	        block.nTime = nTime;
369	        block.nBits = nBits;
370	        block.nNonce = nNonce;
371	        return block.GetHash();
372	    }
373	
374	    uint256 GetBlockHash() = delete;
375	    std::string ToString() = delete;
376	};
