5763	
5764	util::Result<void> ChainstateManager::PopulateAndValidateSnapshot(
5765	    Chainstate& snapshot_chainstate,
5766	    AutoFile& coins_file,
5767	    const SnapshotMetadata& metadata)
5768	{
5769	    // It's okay to release cs_main before we're done using `coins_cache` because we know
5770	    // that nothing else will be referencing the newly created snapshot_chainstate yet.
5771	    CCoinsViewCache& coins_cache = *WITH_LOCK(::cs_main, return &snapshot_chainstate.CoinsTip());
5772	
5773	    uint256 base_blockhash = metadata.m_base_blockhash;
5774	
5775	    CBlockIndex* snapshot_start_block = WITH_LOCK(::cs_main, return m_blockman.LookupBlockIndex(base_blockhash));
5776	
5777	    if (!snapshot_start_block) {
5778	        // Needed for ComputeUTXOStats to determine the
5779	        // height and to avoid a crash when base_blockhash.IsNull()
5780	        return util::Error{Untranslated(strprintf("Did not find snapshot start blockheader %s",
5781	                  base_blockhash.ToString()))};
5782	    }
5783	
5784	    int base_height = snapshot_start_block->nHeight;
5785	    const auto& maybe_au_data = GetParams().AssumeutxoForHeight(base_height);
5786	
5787	    if (!maybe_au_data) {
5788	        return util::Error{Untranslated(strprintf("Assumeutxo height in snapshot metadata not recognized "
5789	                  "(%d) - refusing to load snapshot", base_height))};
5790	    }
5791	
5792	    const AssumeutxoData& au_data = *maybe_au_data;
5793	
5794	    // This work comparison is a duplicate check with the one performed later in
5795	    // ActivateSnapshot(), but is done so that we avoid doing the long work of staging
5796	    // a snapshot that isn't actually usable.
5797	    if (WITH_LOCK(::cs_main, return !CBlockIndexWorkComparator()(ActiveTip(), snapshot_start_block))) {
5798	        return util::Error{Untranslated("Work does not exceed active chainstate")};
5799	    }
5800	
5801	    const uint64_t coins_count = metadata.m_coins_count;
5802	    uint64_t coins_left = metadata.m_coins_count;
5803	
5804	    LogInfo("[snapshot] loading %d coins from snapshot %s", coins_left, base_blockhash.ToString());
5805	    int64_t coins_processed{0};
5806	
5807	    while (coins_left > 0) {
5808	        try {
5809	            Txid txid;
5810	            coins_file >> txid;
5811	            size_t coins_per_txid{0};
5812	            coins_per_txid = ReadCompactSize(coins_file);
5813	
5814	            if (coins_per_txid > coins_left) {
5815	                return util::Error{Untranslated("Mismatch in coins count in snapshot metadata and actual snapshot data")};
5816	            }
5817	
5818	            for (size_t i = 0; i < coins_per_txid; i++) {
5819	                COutPoint outpoint;
5820	                Coin coin;
5821	                outpoint.n = static_cast<uint32_t>(ReadCompactSize(coins_file));
5822	                outpoint.hash = txid;
5823	                coins_file >> coin;
5824	                if (coin.nHeight > base_height ||
5825	                    outpoint.n >= std::numeric_limits<decltype(outpoint.n)>::max() // Avoid integer wrap-around in coinstats.cpp:ApplyHash
5826	                ) {
5827	                    return util::Error{Untranslated(strprintf("Bad snapshot data after deserializing %d coins",
5828	                              coins_count - coins_left))};
5829	                }
5830	                if (!MoneyRange(coin.out.nValue)) {
5831	                    return util::Error{Untranslated(strprintf("Bad snapshot data after deserializing %d coins - bad tx out value",
5832	                              coins_count - coins_left))};
5833	                }
5834	                coins_cache.EmplaceCoinInternalDANGER(std::move(outpoint), std::move(coin));
5835	
5836	                --coins_left;
5837	                ++coins_processed;
5838	
5839	                if (coins_processed % 1000000 == 0) {
5840	                    LogInfo("[snapshot] %d coins loaded (%.2f%%, %.2f MB)",
5841	                        coins_processed,
5842	                        static_cast<float>(coins_processed) * 100 / static_cast<float>(coins_count),
5843	                        coins_cache.DynamicMemoryUsage() / (1000 * 1000));
5844	                }
5845	
5846	                // Batch write and flush (if we need to) every so often.
5847	                //
5848	                // If our average Coin size is roughly 41 bytes, checking every 120,000 coins
5849	                // means <5MB of memory imprecision.
5850	                if (coins_processed % 120000 == 0) {
5851	                    if (m_interrupt) {
5852	                        return util::Error{Untranslated("Aborting after an interrupt was requested")};
5853	                    }
5854	
5855	                    const auto snapshot_cache_state = WITH_LOCK(::cs_main,
5856	                        return snapshot_chainstate.GetCoinsCacheSizeState());
5857	
5858	                    if (snapshot_cache_state >= CoinsCacheSizeState::CRITICAL) {
5859	                        // This is a hack - we don't know what the actual best block is, but that
5860	                        // doesn't matter for the purposes of flushing the cache here. We'll set this
5861	                        // to its correct value (`base_blockhash`) below after the coins are loaded.
5862	                        coins_cache.SetBestBlock(GetRandHash());
5863	
5864	                        // No need to acquire cs_main since this chainstate isn't being used yet.
5865	                        FlushSnapshotToDisk(coins_cache, /*snapshot_loaded=*/false);
5866	                    }
5867	                }
5868	            }
5869	        } catch (const std::ios_base::failure&) {
5870	            return util::Error{Untranslated(strprintf("Bad snapshot format or truncated snapshot after deserializing %d coins",
5871	                      coins_processed))};
5872	        }
5873	    }
5874	
5875	    // Important that we set this. This and the coins_cache accesses above are
5876	    // sort of a layer violation, but either we reach into the innards of
5877	    // CCoinsViewCache here or we have to invert some of the Chainstate to
5878	    // embed them in a snapshot-activation-specific CCoinsViewCache bulk load
5879	    // method.
5880	    coins_cache.SetBestBlock(base_blockhash);
5881	
5882	    bool out_of_coins{false};
5883	    try {
5884	        std::byte left_over_byte;
5885	        coins_file >> left_over_byte;
5886	    } catch (const std::ios_base::failure&) {
5887	        // We expect an exception since we should be out of coins.
5888	        out_of_coins = true;
5889	    }
5890	    if (!out_of_coins) {
5891	        return util::Error{Untranslated(strprintf("Bad snapshot - coins left over after deserializing %d coins",
5892	            coins_count))};
5893	    }
5894	
5895	    LogInfo("[snapshot] loaded %d (%.2f MB) coins from snapshot %s",
5896	        coins_count,
5897	        coins_cache.DynamicMemoryUsage() / (1000 * 1000),
5898	        base_blockhash.ToString());
5899	
5900	    // No need to acquire cs_main since this chainstate isn't being used yet.
5901	    FlushSnapshotToDisk(coins_cache, /*snapshot_loaded=*/true);
5902	
5903	    assert(coins_cache.GetBestBlock() == base_blockhash);
5904	
5905	    // As above, okay to immediately release cs_main here since no other context knows
5906	    // about the snapshot_chainstate.
5907	    CCoinsViewDB* snapshot_coinsdb = WITH_LOCK(::cs_main, return &snapshot_chainstate.CoinsDB());
5908	
5909	    std::optional<CCoinsStats> maybe_stats;
5910	
5911	    try {
5912	        maybe_stats = ComputeUTXOStats(
5913	            CoinStatsHashType::HASH_SERIALIZED, snapshot_coinsdb, m_blockman, [&interrupt = m_interrupt] { SnapshotUTXOHashBreakpoint(interrupt); });
5914	    } catch (StopHashingException const&) {
5915	        return util::Error{Untranslated("Aborting after an interrupt was requested")};
5916	    }
5917	    if (!maybe_stats.has_value()) {
5918	        return util::Error{Untranslated("Failed to generate coins stats")};
5919	    }
5920	
5921	    // Assert that the deserialized chainstate contents match the expected assumeutxo value.
5922	    if (AssumeutxoHash{maybe_stats->hashSerialized} != au_data.hash_serialized) {
5923	        return util::Error{Untranslated(strprintf("Bad snapshot content hash: expected %s, got %s",
5924	            au_data.hash_serialized.ToString(), maybe_stats->hashSerialized.ToString()))};
5925	    }
5926	
5927	    snapshot_chainstate.m_chain.SetTip(*snapshot_start_block);
5928	
5929	    // The remainder of this function requires modifying data protected by cs_main.
5930	    LOCK(::cs_main);
5931	
5932	    // Fake various pieces of CBlockIndex state:
5933	    CBlockIndex* index = nullptr;
5934	
5935	    // Don't make any modifications to the genesis block since it shouldn't be
5936	    // necessary, and since the genesis block doesn't have normal flags like
5937	    // BLOCK_VALID_SCRIPTS set.
5938	    constexpr int AFTER_GENESIS_START{1};
5939	
5940	    for (int i = AFTER_GENESIS_START; i <= snapshot_chainstate.m_chain.Height(); ++i) {
5941	        index = snapshot_chainstate.m_chain[i];
5942	
5943	        // Fake BLOCK_OPT_WITNESS so that Chainstate::NeedsRedownload()
5944	        // won't ask for -reindex on startup.
5945	        if (DeploymentActiveAt(*index, *this, Consensus::DEPLOYMENT_SEGWIT)) {
5946	            index->nStatus |= BLOCK_OPT_WITNESS;
5947	        }
5948	
5949	        m_blockman.m_dirty_blockindex.insert(index);
5950	        // Changes to the block index will be flushed to disk after this call
5951	        // returns in `ActivateSnapshot()`, when `MaybeRebalanceCaches()` is
5952	        // called, since we've added a snapshot chainstate and therefore will
5953	        // have to downsize the IBD chainstate, which will result in a call to
5954	        // `FlushStateToDisk(FORCE_FLUSH)`.
5955	    }
5956	
5957	    assert(index);
5958	    assert(index == snapshot_start_block);
5959	    index->m_chain_tx_count = au_data.m_chain_tx_count;
5960	
5961	    LogInfo("[snapshot] validated snapshot (%.2f MB)",
5962	        coins_cache.DynamicMemoryUsage() / (1000 * 1000));
5963	    return {};
5964	}
5965	
5966	// Currently, this function holds cs_main for its duration, which could be for
5967	// multiple minutes due to the ComputeUTXOStats call. Holding cs_main used to be
5968	// necessary (before d43a1f1a2fa3) to avoid advancing validated_cs farther than
5969	// its target block. Now it should be possible to avoid this, but simply
5970	// releasing cs_main here would not be possible because this function is invoked
5971	// by ConnectTip within ActivateBestChain.
5972	//
5973	// Eventually (TODO) it would be better to call this function outside of
5974	// ActivateBestChain, on a separate thread that should not require cs_main to
5975	// hash, because the UTXO set is only hashed after the historical chainstate
5976	// reaches its target block and is no longer changing.
5977	SnapshotCompletionResult ChainstateManager::MaybeValidateSnapshot(Chainstate& validated_cs, Chainstate& unvalidated_cs)
5978	{
5979	    AssertLockHeld(cs_main);
5980	
5981	    // If the snapshot does not need to be validated...
5982	    if (unvalidated_cs.m_assumeutxo != Assumeutxo::UNVALIDATED ||
5983	            // Or if either chainstate is unusable...
5984	            !unvalidated_cs.m_from_snapshot_blockhash ||
5985	            validated_cs.m_assumeutxo != Assumeutxo::VALIDATED ||
5986	            !validated_cs.m_chain.Tip() ||
5987	            // Or the validated chainstate is not targeting the snapshot block...
5988	            !validated_cs.m_target_blockhash ||
5989	            *validated_cs.m_target_blockhash != *unvalidated_cs.m_from_snapshot_blockhash ||
5990	            // Or the validated chainstate has not reached the snapshot block yet...
5991	            !validated_cs.ReachedTarget()) {
5992	       // Then the snapshot cannot be validated and there is nothing to do.
5993	       return SnapshotCompletionResult::SKIPPED;
5994	    }
5995	    assert(validated_cs.TargetBlock() == validated_cs.m_chain.Tip());
5996	
5997	    auto handle_invalid_snapshot = [&]() EXCLUSIVE_LOCKS_REQUIRED(::cs_main) {
5998	        bilingual_str user_error = strprintf(_(
5999	            "%s failed to validate the -assumeutxo snapshot state. "
6000	            "This indicates a hardware problem, or a bug in the software, or a "
6001	            "bad software modification that allowed an invalid snapshot to be "
6002	            "loaded. As a result of this, the node will shut down and stop using any "
6003	            "state that was built on the snapshot, resetting the chain height "
6004	            "from %d to %d. On the next "
6005	            "restart, the node will resume syncing from %d "
6006	            "without using any snapshot data. "
6007	            "Please report this incident to %s, including how you obtained the snapshot. "
6008	            "The invalid snapshot chainstate will be left on disk in case it is "
6009	            "helpful in diagnosing the issue that caused this error."),
6010	            CLIENT_NAME, unvalidated_cs.m_chain.Height(),
6011	            validated_cs.m_chain.Height(),
6012	            validated_cs.m_chain.Height(), CLIENT_BUGREPORT);
6013	
6014	        LogError("[snapshot] !!! %s\n", user_error.original);
6015	        LogError("[snapshot] deleting snapshot, reverting to validated chain, and stopping node\n");
6016	
6017	        // Reset chainstate target to network tip instead of snapshot block.
6018	        validated_cs.SetTargetBlock(nullptr);
6019	
6020	        unvalidated_cs.m_assumeutxo = Assumeutxo::INVALID;
6021	
6022	        auto rename_result = unvalidated_cs.InvalidateCoinsDBOnDisk();
6023	        if (!rename_result) {
6024	            user_error += Untranslated("\n") + util::ErrorString(rename_result);
6025	        }
6026	
6027	        GetNotifications().fatalError(user_error);
6028	    };
6029	
6030	    CCoinsViewDB& validated_coins_db = validated_cs.CoinsDB();
6031	    validated_cs.ForceFlushStateToDisk();
6032	
6033	    const auto& maybe_au_data = m_options.chainparams.AssumeutxoForHeight(validated_cs.m_chain.Height());
6034	    if (!maybe_au_data) {
6035	        LogWarning("[snapshot] assumeutxo data not found for height "
6036	            "(%d) - refusing to validate snapshot", validated_cs.m_chain.Height());
6037	        handle_invalid_snapshot();
6038	        return SnapshotCompletionResult::MISSING_CHAINPARAMS;
6039	    }
6040	
6041	    const AssumeutxoData& au_data = *maybe_au_data;
6042	    std::optional<CCoinsStats> validated_cs_stats;
6043	    LogInfo("[snapshot] computing UTXO stats for background chainstate to validate "
6044	        "snapshot - this could take a few minutes");
6045	    try {
6046	        validated_cs_stats = ComputeUTXOStats(
6047	            CoinStatsHashType::HASH_SERIALIZED,
6048	            &validated_coins_db,
6049	            m_blockman,
6050	            [&interrupt = m_interrupt] { SnapshotUTXOHashBreakpoint(interrupt); });
6051	    } catch (StopHashingException const&) {
6052	        return SnapshotCompletionResult::STATS_FAILED;
6053	    }
6054	
6055	    // XXX note that this function is slow and will hold cs_main for potentially minutes.
6056	    if (!validated_cs_stats) {
6057	        LogWarning("[snapshot] failed to generate stats for validation coins db");
6058	        // While this isn't a problem with the snapshot per se, this condition
6059	        // prevents us from validating the snapshot, so we should shut down and let the
6060	        // user handle the issue manually.
6061	        handle_invalid_snapshot();
6062	        return SnapshotCompletionResult::STATS_FAILED;
6063	    }
6064	
6065	    // Compare the validated chainstate's UTXO set hash against the hard-coded
6066	    // assumeutxo hash we expect.
6067	    //
6068	    // TODO: For belt-and-suspenders, we could cache the UTXO set
6069	    // hash for the snapshot when it's loaded in its chainstate's leveldb. We could then
6070	    // reference that here for an additional check.
6071	    if (AssumeutxoHash{validated_cs_stats->hashSerialized} != au_data.hash_serialized) {
6072	        LogWarning("[snapshot] hash mismatch: actual=%s, expected=%s",
6073	            validated_cs_stats->hashSerialized.ToString(),
6074	            au_data.hash_serialized.ToString());
6075	        handle_invalid_snapshot();
6076	        return SnapshotCompletionResult::HASH_MISMATCH;
6077	    }
6078	
6079	    LogInfo("[snapshot] snapshot beginning at %s has been fully validated",
6080	        unvalidated_cs.m_from_snapshot_blockhash->ToString());
6081	
6082	    unvalidated_cs.m_assumeutxo = Assumeutxo::VALIDATED;
6083	    validated_cs.m_target_utxohash = AssumeutxoHash{validated_cs_stats->hashSerialized};
6084	    this->MaybeRebalanceCaches();
6085	
6086	    return SnapshotCompletionResult::SUCCESS;
6087	}
