6357	std::pair<int, int> Chainstate::GetPruneRange(int last_height_can_prune) const
6358	{
6359	    if (m_chain.Height() <= 0) {
6360	        return {0, 0};
6361	    }
6362	    int prune_start{0};
6363	
6364	    if (m_from_snapshot_blockhash && m_assumeutxo != Assumeutxo::VALIDATED) {
6365	        // Only prune blocks _after_ the snapshot if this is a snapshot chain
6366	        // that has not been fully validated yet. The earlier blocks need to be
6367	        // kept to validate the snapshot
6368	        prune_start = Assert(SnapshotBase())->nHeight + 1;
6369	    }
6370	
6371	    int max_prune = std::max<int>(
6372	        0, m_chain.Height() - static_cast<int>(MIN_BLOCKS_TO_KEEP));
6373	
6374	    // last block to prune is the lesser of (caller-specified height, MIN_BLOCKS_TO_KEEP from the tip)
6375	    //
6376	    // While you might be tempted to prune the background chainstate more
6377	    // aggressively (i.e. fewer MIN_BLOCKS_TO_KEEP), this won't work with index
6378	    // building - specifically blockfilterindex requires undo data, and if
6379	    // we don't maintain this trailing window, we hit indexing failures.
6380	    int prune_end = std::min(last_height_can_prune, max_prune);
6381	
6382	    return {prune_start, prune_end};
6383	}
