5764	util::Result<void> ChainstateManager::PopulateAndValidateSnapshot(
5765	    Chainstate& snapshot_chainstate,
5766	    AutoFile& coins_file,
5767	    const SnapshotMetadata& metadata)
5768	{
5769	    // It's okay to release cs_main before we're done using `coins_cache` because we know
5770	    // that nothing else will be referencing the newly created snapshot_chainstate yet.
5771	    CCoinsViewCache& coins_cache = *WITH_LOCK(::cs_main, return &snapshot_chainstate.CoinsTip());
5772	
5773	    uint256 base_blockhash = metadata.m_base_blockhash;
5774	
5775	    CBlockIndex* snapshot_start_block = WITH_LOCK(::cs_main, return m_blockman.LookupBlockIndex(base_blockhash));
5776	
5777	    if (!snapshot_start_block) {
5778	        // Needed for ComputeUTXOStats to determine the
5779	        // height and to avoid a crash when base_blockhash.IsNull()
5780	        return util::Error{Untranslated(strprintf("Did not find snapshot start blockheader %s",
5781	                  base_blockhash.ToString()))};
5782	    }
5783	
5784	    int base_height = snapshot_start_block->nHeight;
5785	    const auto& maybe_au_data = GetParams().AssumeutxoForHeight(base_height);
5786	
5787	    if (!maybe_au_data) {
5788	        return util::Error{Untranslated(strprintf("Assumeutxo height in snapshot metadata not recognized "
5789	                  "(%d) - refusing to load snapshot", base_height))};
5790	    }
5791	
5792	    const AssumeutxoData& au_data = *maybe_au_data;
5793	
5794	    // This work comparison is a duplicate check with the one performed later in
5795	    // ActivateSnapshot(), but is done so that we avoid doing the long work of staging
5796	    // a snapshot that isn't actually usable.
5797	    if (WITH_LOCK(::cs_main, return !CBlockIndexWorkComparator()(ActiveTip(), snapshot_start_block))) {
5798	        return util::Error{Untranslated("Work does not exceed active chainstate")};
5799	    }
5800	
5801	    const uint64_t coins_count = metadata.m_coins_count;
5802	    uint64_t coins_left = metadata.m_coins_count;
5803	
5804	    LogInfo("[snapshot] loading %d coins from snapshot %s", coins_left, base_blockhash.ToString());
5805	    int64_t coins_processed{0};
5806	
5807	    while (coins_left > 0) {
5808	        try {
5809	            Txid txid;
5810	            coins_file >> txid;
5811	            size_t coins_per_txid{0};
5812	            coins_per_txid = ReadCompactSize(coins_file);
5813	
5814	            if (coins_per_txid > coins_left) {
5815	                return util::Error{Untranslated("Mismatch in coins count in snapshot metadata and actual snapshot data")};
5816	            }
5817	
5818	            for (size_t i = 0; i < coins_per_txid; i++) {
5819	                COutPoint outpoint;
5820	                Coin coin;
5821	                outpoint.n = static_cast<uint32_t>(ReadCompactSize(coins_file));
5822	                outpoint.hash = txid;
5823	                coins_file >> coin;
5824	                if (coin.nHeight > base_height ||
5825	                    outpoint.n >= std::numeric_limits<decltype(outpoint.n)>::max() // Avoid integer wrap-around in coinstats.cpp:ApplyHash
5826	                ) {
5827	                    return util::Error{Untranslated(strprintf("Bad snapshot data after deserializing %d coins",
5828	                              coins_count - coins_left))};
5829	                }
5830	                if (!MoneyRange(coin.out.nValue)) {
5831	                    return util::Error{Untranslated(strprintf("Bad snapshot data after deserializing %d coins - bad tx out value",
5832	                              coins_count - coins_left))};
5833	                }
5834	                coins_cache.EmplaceCoinInternalDANGER(std::move(outpoint), std::move(coin));
5835	
5836	                --coins_left;
5837	                ++coins_processed;
5838	
5839	                if (coins_processed % 1000000 == 0) {
5840	                    LogInfo("[snapshot] %d coins loaded (%.2f%%, %.2f MB)",
5841	                        coins_processed,
5842	                        static_cast<float>(coins_processed) * 100 / static_cast<float>(coins_count),
5843	                        coins_cache.DynamicMemoryUsage() / (1000 * 1000));
5844	                }
5845	
5846	                // Batch write and flush (if we need to) every so often.
5847	                //
5848	                // If our average Coin size is roughly 41 bytes, checking every 120,000 coins
5849	                // means <5MB of memory imprecision.

2950	    assert(pindexDelete->pprev);
2951	    // Read block from disk.
2952	    std::shared_ptr<CBlock> pblock = std::make_shared<CBlock>();
2953	    CBlock& block = *pblock;
2954	    if (!m_blockman.ReadBlock(block, *pindexDelete)) {
2955	        LogError("DisconnectTip(): Failed to read block\n");
2956	        return false;
2957	    }
2958	    // Apply the block atomically to the chain state.
2959	    const auto time_start{SteadyClock::now()};
2960	    {
2961	        CCoinsViewCache view(&CoinsTip());
2962	        assert(view.GetBestBlock() == pindexDelete->GetBlockHash());
2963	        if (DisconnectBlock(block, pindexDelete, view) != DISCONNECT_OK) {
2964	            LogError("DisconnectTip(): DisconnectBlock %s failed\n", pindexDelete->GetBlockHash().ToString());
2965	            return false;
2966	        }
2967	        view.Flush(/*reallocate_cache=*/false); // local CCoinsViewCache goes out of scope
2968	    }
2969	    LogDebug(BCLog::BENCH, "- Disconnect block: %.2fms\n",
2970	             Ticks<MillisecondsDouble>(SteadyClock::now() - time_start));
2971	
2972	    {
2973	        // Prune locks that began at or after the tip should be moved backward so they get a chance to reorg
2974	        const int max_height_first{pindexDelete->nHeight - 1};
2975	        for (auto& prune_lock : m_blockman.m_prune_locks) {
2976	            if (prune_lock.second.height_first <= max_height_first) continue;
2977	
2978	            prune_lock.second.height_first = max_height_first;
2979	            LogDebug(BCLog::PRUNE, "%s prune lock moved back to %d\n", prune_lock.first, max_height_first);
2980	        }
2981	    }
2982	
2983	    // Write the chain state to disk, if necessary.
2984	    if (!FlushStateToDisk(state, FlushStateMode::IF_NEEDED)) {
2985	        return false;
2986	    }
2987	
2988	    if (disconnectpool && m_mempool) {
2989	        // Save transactions to re-add to mempool at end of reorg. If any entries are evicted for
2990	        // exceeding memory limits, remove them and their descendants from the mempool.
2991	        for (auto&& evicted_tx : disconnectpool->AddTransactionsFromBlock(block.vtx)) {
2992	            m_mempool->removeRecursive(*evicted_tx, MemPoolRemovalReason::REORG);
2993	        }
2994	    }
2995	
2996	    m_chain.SetTip(*pindexDelete->pprev);
2997	    m_chainman.UpdateIBDStatus();
2998	
2999	    UpdateTip(pindexDelete->pprev);
3000	    // Let wallets know transactions went from 1-confirmed to
3001	    // 0-confirmed or conflicted:
3002	    if (m_chainman.m_options.signals) {
3003	        m_chainman.m_options.signals->BlockDisconnected(std::move(pblock), pindexDelete);
3004	    }
3005	    return true;
3006	}
